(function () {
  'use strict';

  const KIT_VERSION = '2.1.0';
  const ZIP_NAME    = 'Iconik-Sync-Kit.zip';

const KIT_FILES = {
  "sync_dd_standalone.html": "<!DOCTYPE html>\n<html lang=\"fr\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Iconik Sync — PROD → DEV</title>\n  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n    :root {\n      --bg:#0e0e0e; --bg2:#161616; --bg3:#1e1e1e;\n      --border:#2a2a2a; --border2:#333;\n      --text:#e8e8e8; --text-dim:#888;\n      --accent:#00d4aa; --c-warn:#f39c12; --c-danger:#e74c3c;\n      --font:'Courier New',monospace;\n    }\n    body { background:var(--bg); color:var(--text); font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif; font-size:13px; min-height:100vh; display:flex; flex-direction:column; align-items:center; padding:28px 16px; }\n    .header { text-align:center; margin-bottom:24px; }\n    .header h1 { font-size:20px; font-weight:700; color:var(--accent); }\n    .header p { font-size:11px; color:var(--text-dim); margin-top:4px; }\n    .dir-badge { display:inline-flex; align-items:center; gap:10px; margin-top:8px; padding:5px 14px; background:rgba(0,212,170,.08); border:1px solid rgba(0,212,170,.3); border-radius:20px; font-size:11px; font-weight:600; color:var(--accent); }\n    .card { width:100%; max-width:740px; background:var(--bg2); border:1px solid var(--border2); border-radius:7px; padding:18px; margin-bottom:14px; }\n    .card-title { font-size:10px; font-weight:700; text-transform:uppercase; letter-spacing:.08em; color:var(--text-dim); margin-bottom:12px; }\n    .creds-grid { display:grid; grid-template-columns:1fr 1fr; gap:14px; }\n    @media(max-width:580px){ .creds-grid{grid-template-columns:1fr;} }\n    .env-block { background:var(--bg3); border:1px solid var(--border); border-radius:5px; padding:12px; }\n    .env-block.prod { border-left:3px solid #27ae60; }\n    .env-block.dev  { border-left:3px solid var(--c-warn); }\n    .env-label { font-size:10px; font-weight:700; text-transform:uppercase; letter-spacing:.06em; margin-bottom:8px; }\n    .env-block.prod .env-label { color:#27ae60; }\n    .env-block.dev  .env-label { color:var(--c-warn); }\n    .field { margin-bottom:8px; }\n    .field label { display:block; font-size:9px; color:var(--text-dim); margin-bottom:2px; text-transform:uppercase; letter-spacing:.04em; }\n    .field input { width:100%; padding:6px 8px; background:var(--bg); border:1px solid var(--border2); border-radius:3px; color:var(--text); font-size:11px; font-family:var(--font); }\n    .field input:focus { outline:none; border-color:var(--accent); }\n    .scopes-wrap { display:flex; flex-wrap:wrap; gap:5px; }\n    .scope-pill { display:flex; align-items:center; gap:4px; font-size:10px; cursor:pointer; color:var(--text-dim); padding:3px 8px; background:var(--bg3); border:1px solid var(--border); border-radius:3px; }\n    .scope-pill input { cursor:pointer; }\n    .scope-actions { display:flex; gap:6px; margin-top:8px; }\n    .scope-actions button { font-size:10px; padding:3px 9px; background:var(--bg3); border:1px solid var(--border2); border-radius:3px; color:var(--text-dim); cursor:pointer; }\n    .opts-row { display:flex; align-items:center; gap:12px; flex-wrap:wrap; font-size:11px; color:var(--text-dim); }\n    .opts-row select { padding:4px 8px; background:var(--bg3); border:1px solid var(--border2); border-radius:3px; color:var(--text); font-size:11px; }\n    .mode-warn { font-size:10px; color:var(--c-warn); padding:4px 10px; background:rgba(243,156,18,.07); border:1px solid rgba(243,156,18,.2); border-radius:3px; display:none; margin-top:6px; }\n    .btn-run { width:100%; max-width:740px; padding:13px; background:var(--accent); color:#000; border:none; border-radius:5px; font-size:13px; font-weight:700; cursor:pointer; margin-bottom:14px; }\n    .btn-run:disabled { opacity:.35; cursor:not-allowed; }\n    .progress-wrap { width:100%; max-width:740px; display:none; margin-bottom:12px; }\n    .pb-bg { height:5px; background:var(--bg3); border-radius:3px; overflow:hidden; margin-bottom:5px; }\n    .pb-fill { height:100%; background:var(--accent); border-radius:3px; width:0%; transition:width .4s; }\n    .pb-label { font-size:10px; color:var(--text-dim); text-align:center; }\n    .result-banner { width:100%; max-width:740px; padding:12px 16px; border-radius:5px; display:none; align-items:center; gap:10px; margin-bottom:14px; font-size:12px; font-weight:600; }\n    .result-banner.ok  { background:rgba(0,212,170,.08); border:1px solid var(--accent); color:var(--accent); }\n    .result-banner.err { background:rgba(231,76,60,.08); border:1px solid var(--c-danger); color:var(--c-danger); }\n    .log-card { width:100%; max-width:740px; display:none; }\n    .log-box { background:#060606; border:1px solid var(--border); border-radius:5px; padding:10px 12px; font-family:var(--font); font-size:11px; max-height:360px; overflow-y:auto; line-height:1.9; }\n    .l-ok    { color:var(--accent); }\n    .l-err   { color:var(--c-danger); }\n    .l-warn  { color:var(--c-warn); }\n    .l-info  { color:var(--text-dim); }\n    .l-title { color:var(--accent); font-weight:700; }\n    footer { margin-top:24px; font-size:9px; color:#444; text-align:center; }\n    .mirror-row { display:flex; align-items:center; gap:12px; flex-wrap:wrap; margin-bottom:10px; }\n    .btn-mirror { padding:8px 18px; background:transparent; color:#3498db; border:1px solid #3498db; border-radius:4px; font-size:12px; font-weight:600; cursor:pointer; }\n    .btn-mirror:hover { background:rgba(52,152,219,.1); }\n    .btn-mirror:disabled { opacity:.35; cursor:not-allowed; }\n    .mirror-opt { font-size:11px; color:var(--text-dim); display:flex; align-items:center; gap:5px; cursor:pointer; }\n    .mirror-note { font-size:10px; color:var(--text-dim); margin-top:6px; }\n    .l-check-head { color:#3498db; font-weight:700; }\n    .l-check-ok   { color:var(--accent); }\n    .l-check-diff { color:var(--c-warn); }\n    .l-check-miss { color:var(--c-danger); }\n    .token-check { display:flex; align-items:center; gap:6px; font-size:10px; margin-top:5px; min-height:16px; }\n    .tc-ok   { color:var(--accent); }\n    .tc-warn { color:var(--c-warn); font-weight:600; }\n    .tc-err  { color:var(--c-danger); }\n    .tc-spin { color:var(--text-dim); }\n  </style>\n</head>\n<body>\n\n<div class=\"header\">\n  <h1>🔄 Iconik Sync</h1>\n  <p>Synchronisation de configuration entre environnements</p>\n  <div class=\"dir-badge\">🟢 PRODUCTION &nbsp;→&nbsp; 🟡 DEV / STAGING</div>\n</div>\n\n<div class=\"card\">\n  <div class=\"card-title\">🔑 Connexion</div>\n  <div class=\"creds-grid\">\n    <div class=\"env-block prod\">\n      <div class=\"env-label\">🟢 Source — Production</div>\n      <div class=\"field\"><label>Nom</label><input type=\"text\" id=\"prod-name\" value=\"PROD\"></div>\n      <div class=\"field\"><label>URL Iconik</label><input type=\"text\" id=\"prod-url\" value=\"https://app.iconik.io\"></div>\n      <div class=\"field\"><label>App ID</label><input type=\"text\" id=\"prod-appid\" autocomplete=\"off\" oninput=\"scheduleTokenCheck('prod')\"></div>\n      <div class=\"field\"><label>Auth Token</label><input type=\"password\" id=\"prod-token\" autocomplete=\"off\" oninput=\"scheduleTokenCheck('prod')\"></div>\n      <div class=\"token-check\" id=\"prod-token-check\"></div>\n    </div>\n    <div class=\"env-block dev\">\n      <div class=\"env-label\">🟡 Destination — Dev / Staging</div>\n      <div class=\"field\"><label>Nom</label><input type=\"text\" id=\"dev-name\" value=\"DEV\"></div>\n      <div class=\"field\"><label>URL Iconik</label><input type=\"text\" id=\"dev-url\" value=\"https://app.iconik.io\"></div>\n      <div class=\"field\"><label>App ID</label><input type=\"text\" id=\"dev-appid\" autocomplete=\"off\" oninput=\"scheduleTokenCheck('dev')\"></div>\n      <div class=\"field\"><label>Auth Token</label><input type=\"password\" id=\"dev-token\" autocomplete=\"off\" oninput=\"scheduleTokenCheck('dev')\"></div>\n      <div class=\"token-check\" id=\"dev-token-check\"></div>\n    </div>\n  </div>\n</div>\n\n<div class=\"card\">\n  <div class=\"card-title\">📋 Périmètre</div>\n  <div class=\"scopes-wrap\" id=\"scopes-wrap\"></div>\n  <div class=\"scope-actions\">\n    <button onclick=\"toggleAll(true)\">Tout cocher</button>\n    <button onclick=\"toggleAll(false)\">Tout décocher</button>\n  </div>\n</div>\n\n<div class=\"card\">\n  <div class=\"card-title\">⚙️ Options</div>\n  <div class=\"opts-row\">\n    <label>Mode :</label>\n    <select id=\"sync-mode\" onchange=\"onModeChange(this)\">\n      <option value=\"add_update\" selected>🔄 Ajouter + Mettre à jour</option>\n      <option value=\"add_only\">➕ Ajouter uniquement</option>\n      <option value=\"overwrite\">⚠️ Écraser tout</option>\n    </select>\n    <label style=\"display:flex;align-items:center;gap:5px;cursor:pointer;\">\n      <input type=\"checkbox\" id=\"dry-run\"> Dry-run\n    </label>\n  </div>\n  <div class=\"mode-warn\" id=\"mode-warn\">\n    ⚠️ Supprime tout en destination (sauf teams avec utilisateurs) puis recrée depuis la source\n  </div>\n</div>\n\n<div class=\"card\">\n  <div class=\"card-title\">🔍 Mirror Check</div>\n  <div class=\"mirror-row\">\n    <button class=\"btn-mirror\" id=\"btn-mirror\" onclick=\"lancerMirrorCheck()\">🔍 Lancer le Mirror Check</button>\n    <label class=\"mirror-opt\"><input type=\"checkbox\" id=\"mirror-acl\"> 🔐 Vérifier les ACLs (collections, MD views, saved searches, custom actions &amp; export locations)</label>\n  </div>\n  <div class=\"mirror-note\">Check rapide : présence/absence + paramètres — Check profond (🔐) : ajoute la comparaison ACLs pour collections, MD views, saved searches, custom actions et export locations</div>\n</div>\n\n<button class=\"btn-run\" id=\"btn-run\" onclick=\"lancerSync()\">\n  🚀 Lancer la synchronisation PROD → DEV\n</button>\n\n<div class=\"progress-wrap\" id=\"progress-wrap\">\n  <div class=\"pb-bg\"><div class=\"pb-fill\" id=\"pb-fill\"></div></div>\n  <div class=\"pb-label\" id=\"pb-label\">Démarrage…</div>\n</div>\n\n<div class=\"result-banner\" id=\"result-banner\">\n  <span id=\"result-icon\" style=\"font-size:20px;\"></span>\n  <span id=\"result-text\"></span>\n</div>\n\n<div class=\"log-card\" id=\"log-card\">\n  <div class=\"card-title\" style=\"margin-bottom:6px;display:flex;align-items:center;justify-content:space-between;\">\n    <span id=\"log-title\">📋 Journal</span>\n    <button onclick=\"exportJournal()\" style=\"font-size:10px;padding:3px 10px;background:var(--bg3);border:1px solid var(--border2);border-radius:3px;color:var(--text-dim);cursor:pointer;\">💾 Exporter</button>\n  </div>\n  <div class=\"log-box\" id=\"log-box\"></div>\n</div>\n\n<footer>Iconik Sync — PROD → DEV — Propulsé par sync_dd.js</footer>\n\n<script>\nconst SCOPES = [\n  {id:'teams',label:'👥 Teams'},{id:'roleGroups',label:'🎭 Role Groups'},\n  {id:'collections',label:'📁 Collections'},{id:'metadataViews',label:'📋 MD Views'},\n  {id:'metadata',label:'🏷️ Métadonnées'},{id:'savedSearches',label:'🔍 Saved Searches'},\n  {id:'categories',label:'🗂️ Catégories'},{id:'webhooks',label:'🔗 Webhooks'},\n  {id:'customActions',label:'⚡ Custom Actions'},{id:'automations',label:'🤖 Automations'},\n  {id:'relationTypes',label:'🔗 Relation Types'},{id:'systemSettings',label:'⚙️ Share Settings'},\n  {id:'exportLocations',label:'📤 Export Locations'},\n];\n\ndocument.getElementById('scopes-wrap').innerHTML = SCOPES.map(s =>\n  `<label class=\"scope-pill\"><input type=\"checkbox\" class=\"scope-chk\" value=\"${s.id}\" checked>${s.label}</label>`\n).join('');\n\nfunction toggleAll(on) { document.querySelectorAll('.scope-chk').forEach(c => c.checked = on); }\n\nfunction exportJournal() {\n  const lines = Array.from(document.querySelectorAll('#log-box div')).map(el => el.textContent);\n  if (!lines.length) { alert('Le journal est vide.'); return; }\n  const date = new Date().toISOString().slice(0, 19).replace(/[T:]/g, '-');\n  const text = '# Iconik Sync — Journal\\n# ' + date + '\\n\\n' + lines.join('\\n');\n  const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });\n  const a = Object.assign(document.createElement('a'), {\n    href: URL.createObjectURL(blob),\n    download: 'sync-journal-' + date + '.txt'\n  });\n  document.body.appendChild(a); a.click(); document.body.removeChild(a);\n}\nfunction onModeChange(sel) { document.getElementById('mode-warn').style.display = sel.value==='overwrite'?'block':'none'; }\n\nfunction addLog(msg) {\n  const box = document.getElementById('log-box');\n  const el  = document.createElement('div');\n  let cls = 'l-info';\n  if (msg.includes('✅')) cls = 'l-ok';\n  else if (msg.includes('❌')) cls = 'l-err';\n  else if (msg.includes('⚠️')) cls = 'l-warn';\n  else if (msg.includes('──') || msg.includes('══')) cls = 'l-title';\n  el.className = cls;\n  el.textContent = msg;\n  box.appendChild(el);\n  box.scrollTop = box.scrollHeight;\n}\n\nfunction setProgress(pct, label) {\n  document.getElementById('pb-fill').style.width  = pct + '%';\n  document.getElementById('pb-label').textContent = label;\n}\n\n// ── Progression intelligente ─────────────────────────────────────────────────\n// On connaît les scopes à l'avance → on peut calculer un % réel.\n// Les collections comptent pour ~70% du temps total.\nconst SCOPE_WEIGHT = {\n  collections:       40,  // sync hiérarchique\n  acls_collections:  35,  // phase ACL (comparable en durée)\n  metadataViews:      5,\n  metadata:           3,\n  teams:              2,\n  roleGroups:         2,\n  savedSearches:      2,\n  categories:         2,\n  webhooks:           1,\n  customActions:      1,\n  automations:        4,\n  relationTypes:      1,\n  systemSettings:     1,\n};\n\nlet _progressState = null;\n\nfunction initProgress(scopes) {\n  const totalWeight = scopes.reduce((s, sc) => s + (SCOPE_WEIGHT[sc] || 2), 0);\n  const scopeMap = {};\n  let cumul = 0;\n  for (const sc of scopes) {\n    const w = SCOPE_WEIGHT[sc] || 2;\n    scopeMap[sc] = { start: 10 + (cumul / totalWeight) * 85, end: 10 + ((cumul + w) / totalWeight) * 85 };\n    cumul += w;\n  }\n  _progressState = { scopeMap, current: null, pct: 10 };\n}\n\nfunction updateProgress(msg) {\n  if (!_progressState) return;\n  const { scopeMap } = _progressState;\n\n  // Détection début de phase ACL collections (log spécifique)\n  if (msg.includes('── ACLs collections :') && msg.includes('collections à traiter')) {\n    if (scopeMap['acls_collections']) {\n      _progressState.current = 'acls_collections';\n      _progressState.pct = scopeMap['acls_collections'].start;\n      setProgress(Math.round(_progressState.pct), 'ACLs collections…');\n      return;\n    }\n  }\n\n  // Détection début de scope standard : \"── collections…\"\n  const scopeMatch = msg.match(/──\\s+(\\w+)…/);\n  if (scopeMatch) {\n    const sc = scopeMatch[1];\n    if (scopeMap[sc]) {\n      _progressState.current = sc;\n      _progressState.pct = scopeMap[sc].start;\n      setProgress(Math.round(_progressState.pct), sc + '…');\n      return;\n    }\n  }\n\n  // Détection progression X/Y dans les logs\n  const xyMatch = msg.match(/:\\s+(\\d+)\\/(\\d+)/);\n  if (xyMatch && _progressState.current) {\n    const done  = parseInt(xyMatch[1], 10);\n    const total = parseInt(xyMatch[2], 10);\n    if (total > 0) {\n      const sc    = _progressState.current;\n      const range = scopeMap[sc];\n      if (range) {\n        const pct = range.start + (done / total) * (range.end - range.start);\n        _progressState.pct = pct;\n        const isAcl = sc === 'acls_collections';\n        const label = isAcl ? 'ACLs : ' + done + '/' + total\n                    : (sc === 'collections' ? 'Collections : ' : sc + ' : ') + done + '/' + total;\n        setProgress(Math.round(pct), label);\n        return;\n      }\n    }\n  }\n\n  // Fin de scope : \"✅ collections : …\"\n  const doneMatch = msg.match(/✅\\s+(\\w+)/);\n  if (doneMatch) {\n    const sc = doneMatch[1];\n    if (scopeMap[sc]) {\n      _progressState.pct = scopeMap[sc].end;\n      setProgress(Math.round(_progressState.pct), sc + ' ✓');\n    }\n  }\n\n  // Log global de démarrage \"══ Démarrage sync\"\n  if (msg.includes('══')) {\n    setProgress(12, 'Sync démarrée…');\n  }\n}\n\nasync function lancerSync() {\n  const prodAppId = document.getElementById('prod-appid').value.trim();\n  const prodToken = document.getElementById('prod-token').value.trim();\n  const devAppId  = document.getElementById('dev-appid').value.trim();\n  const devToken  = document.getElementById('dev-token').value.trim();\n  const prodName  = document.getElementById('prod-name').value.trim() || 'PROD';\n  const devName   = document.getElementById('dev-name').value.trim()  || 'DEV';\n\n  if (!prodAppId || !prodToken || !devAppId || !devToken) { alert('Remplissez tous les credentials.'); return; }\n  const scopes = Array.from(document.querySelectorAll('.scope-chk:checked')).map(c => c.value);\n  if (!scopes.length) { alert('Cochez au moins un scope.'); return; }\n\n  const mode   = document.getElementById('sync-mode').value;\n  const dryRun = document.getElementById('dry-run').checked;\n\n  if (prodAppId === devAppId) { alert('⛔ Même App ID source et destination !'); return; }\n\n  // Blocage hard si token croisé — pas de confirm(), pas de bypass possible\n  if (hasTokenWarning()) {\n    alert('🚫 Les tokens semblent inversés (PROD dans DEV ou DEV dans PROD).\\nCorrigez les credentials avant de lancer.');\n    return;\n  }\n\n  if (devName.toLowerCase().includes('prod')) {\n    if (prompt('⚠️ Destination semble être PROD !\\nTapez CONFIRMER pour continuer :') !== 'CONFIRMER') { alert('Annulé.'); return; }\n  }\n  if (mode === 'overwrite') {\n    if (prompt('⚠️ MODE OVERWRITE\\nTapez OVERWRITE pour confirmer :') !== 'OVERWRITE') { alert('Annulé.'); return; }\n  }\n  if (!confirm('Synchroniser ' + prodName + ' → ' + devName + '\\nMode : ' + mode + '\\nScopes : ' + scopes.join(', ') + (dryRun ? '\\n\\n⚠️ DRY-RUN' : '') + '\\n\\nConfirmer ?')) return;\n\n  initProgress(scopes);\n\n  document.getElementById('btn-run').disabled    = true;\n  document.getElementById('btn-mirror').disabled = true;\n  document.getElementById('progress-wrap').style.display = 'block';\n  document.getElementById('log-card').style.display = 'block';\n  document.getElementById('result-banner').style.display = 'none';\n  document.getElementById('log-box').innerHTML = '';\n  const _logTitle = document.querySelector('#log-card .card-title span');\n  if (_logTitle) _logTitle.textContent = '📋 Journal — Synchronisation';\n  setProgress(5, 'Envoi au serveur…');\n\n  try {\n    const resp = await fetch('/sync', {\n      method: 'POST',\n      headers: {'Content-Type':'application/json'},\n      body: JSON.stringify({\n        prod_url: document.getElementById('prod-url').value.trim(),\n        prod_app_id: prodAppId, prod_token: prodToken,\n        dev_url:  document.getElementById('dev-url').value.trim(),\n        dev_app_id:  devAppId,  dev_token:  devToken,\n        mode, scopes, dry_run: dryRun,\n      })\n    });\n\n    if (!resp.ok) {\n      const err = await resp.json().catch(() => ({}));\n      addLog('❌ Erreur serveur : ' + (err.error || resp.status));\n      document.getElementById('btn-run').disabled    = false;\n      document.getElementById('btn-mirror').disabled = false;\n      return;\n    }\n\n    setProgress(10, 'Job démarré…');\n    const es = new EventSource('/logs');\n\n    es.onmessage = (e) => {\n      const ev = JSON.parse(e.data);\n      if (ev.type === 'log') {\n        addLog(ev.msg);\n        updateProgress(ev.msg);\n      } else if (ev.type === 'done') {\n        es.close();\n        setProgress(100, 'Terminé');\n        const ok = ev.code === 0;\n        const b = document.getElementById('result-banner');\n        b.className = 'result-banner ' + (ok ? 'ok' : 'err');\n        b.style.display = 'flex';\n        document.getElementById('result-icon').textContent = ok ? '✅' : '⚠️';\n        document.getElementById('result-text').textContent = ok ? 'Sync PROD → DEV terminée avec succès !' : 'Sync terminée avec des erreurs.';\n        document.getElementById('btn-run').disabled    = false;\n        document.getElementById('btn-mirror').disabled = false;\n      } else if (ev.type === 'error') {\n        es.close();\n        addLog('❌ ' + ev.msg);\n        document.getElementById('btn-run').disabled    = false;\n        document.getElementById('btn-mirror').disabled = false;\n      }\n    };\n    es.onerror = () => { es.close(); addLog('❌ Connexion perdue.'); document.getElementById('btn-run').disabled = false; document.getElementById('btn-mirror').disabled = false; };\n\n  } catch (err) {\n    addLog('❌ ' + err.message);\n    document.getElementById('btn-run').disabled    = false;\n    document.getElementById('btn-mirror').disabled = false;\n  }\n}\n\n\n// ══════════════════════════════════════════════════════════════════════════════\n// MIRROR CHECK — Comparaison Source ↔ Destination sans écriture\n// Respecte les scopes cochés. Checkbox \"Vérifier les ACLs\" active\n// la comparaison ACL pour collections et export locations.\n// ══════════════════════════════════════════════════════════════════════════════\n\nasync function lancerMirrorCheck() {\n  const prodAppId = document.getElementById('prod-appid').value.trim();\n  const prodToken = document.getElementById('prod-token').value.trim();\n  const devAppId  = document.getElementById('dev-appid').value.trim();\n  const devToken  = document.getElementById('dev-token').value.trim();\n  const prodName  = document.getElementById('prod-name').value.trim() || 'PROD';\n  const devName   = document.getElementById('dev-name').value.trim()  || 'DEV';\n\n  if (!prodAppId || !prodToken || !devAppId || !devToken) {\n    alert('Remplissez tous les credentials avant de lancer le Mirror Check.');\n    return;\n  }\n  if (prodAppId === devAppId) { alert('⛔ Même App ID source et destination !'); return; }\n\n  const scopes    = Array.from(document.querySelectorAll('.scope-chk:checked')).map(c => c.value);\n  const checkAcls = document.getElementById('mirror-acl').checked;\n\n  document.getElementById('btn-run').disabled    = true;\n  document.getElementById('btn-mirror').disabled = true;\n  document.getElementById('log-card').style.display = 'block';\n  document.getElementById('result-banner').style.display = 'none';\n  document.getElementById('progress-wrap').style.display = 'block';\n  document.getElementById('log-box').innerHTML = '';\n  const _lt = document.getElementById('log-title');\n  if (_lt) _lt.textContent = '🔍 Mirror Check — ' + prodName + ' ↔ ' + devName;\n  setProgress(5, 'Mirror Check démarré…');\n\n  const srcH = { 'App-ID': prodAppId, 'Auth-Token': prodToken, 'Content-Type': 'application/json' };\n  const dstH = { 'App-ID': devAppId,  'Auth-Token': devToken,  'Content-Type': 'application/json' };\n\n  function addCLog(msg, cls) {\n    const box = document.getElementById('log-box');\n    const el  = document.createElement('div');\n    el.className = cls || 'l-info';\n    el.textContent = msg;\n    box.appendChild(el);\n    box.scrollTop = box.scrollHeight;\n  }\n  function logHead(t)  { addCLog('══ ' + t, 'l-check-head'); }\n  function logOk(m)    { addCLog('  ✅ ' + m, 'l-check-ok');   okC++; }\n  function logDiff(m)  { addCLog('  ⚠️ ' + m, 'l-check-diff'); warnC++; }\n  function logMiss(m)  { addCLog('  ❌ ' + m, 'l-check-miss'); errC++; }\n  function logInfo(m)  { addCLog('  ℹ️ ' + m, 'l-info'); }\n\n  let okC = 0, warnC = 0, errC = 0;\n\n  function normN(s) { return String(s || '').trim().toLowerCase(); }\n\n  async function apiFetch(headers, path, method, body) {\n    const opts = { method: method || 'GET', headers };\n    if (body) opts.body = JSON.stringify(body);\n    const r = await fetch(path, opts).catch(() => null);\n    if (!r || !r.ok) return null;\n    return r.json().catch(() => null);\n  }\n\n  async function fetchAll(headers, endpoint) {\n    let page = 1, out = [];\n    while (true) {\n      const sep = endpoint.includes('?') ? '&' : '?';\n      const r = await apiFetch(headers, endpoint + sep + 'per_page=500&page=' + page);\n      if (!r) break;\n      const items = r.objects || r.results || [];\n      if (!items.length) break;\n      out.push(...items);\n      if (items.length < 500) break;\n      page++;\n    }\n    return out;\n  }\n\n  // Compare deux listes, retourne { missing, extra }\n  function compareByName(srcList, dstList, label, opts) {\n    const cs = opts && opts.caseSensitive;\n    const keyFn = cs ? o => String(o.name || o.title || '') : o => normN(o.name || o.title || '');\n    const srcMap = new Map(), dstMap = new Map();\n    srcList.forEach(o => { const k = keyFn(o); if (k) srcMap.set(k, o); });\n    dstList.forEach(o => { const k = keyFn(o); if (k) dstMap.set(k, o); });\n    let missing = 0, extra = 0;\n    srcMap.forEach((o, k) => { if (!dstMap.has(k)) { logMiss(label + ' manquant en dst : ' + (o.name || o.title || k)); missing++; } });\n    dstMap.forEach((o, k) => { if (!srcMap.has(k)) { logDiff(label + ' présent en dst uniquement : ' + (o.name || o.title || k)); extra++; } });\n    if (!missing && !extra) logOk(label + 's : ' + srcMap.size + ' conformes');\n    return { missing, extra, srcMap, dstMap };\n  }\n\n  const SYS_TEAMS = new Set(['everyone', 'administrator']);\n  const SYS_MDVS  = new Set(['segment tags', 'tutorials']);\n\n  // Poids par scope pour la progression\n  const WEIGHT = { teams:2, roleGroups:2, metadata:3, metadataViews:5, savedSearches:2,\n    customActions:1, webhooks:1, automations:3, relationTypes:1, categories:1,\n    systemSettings:1, collections: checkAcls ? 30 : 5, exportLocations: checkAcls ? 5 : 2 };\n  const activeScopes = scopes.filter(s => WEIGHT[s] !== undefined);\n  const totalW = activeScopes.reduce((s, sc) => s + (WEIGHT[sc] || 2), 0);\n  let doneW = 0;\n  function tick(sc) {\n    doneW += (WEIGHT[sc] || 2);\n    setProgress(5 + Math.round((doneW / totalW) * 90), sc + '…');\n  }\n\n  try {\n    addCLog('══ Mirror Check — ' + prodName + ' ↔ ' + devName + (checkAcls ? ' (avec ACLs)' : ' (sans ACLs)'), 'l-check-head');\n\n    // ── Teams ──────────────────────────────────────────────────────────────\n    if (scopes.includes('teams')) {\n      logHead('Teams');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/users/v1/teams/'), fetchAll(dstH, '/API/users/v1/teams/')]);\n      compareByName(src.filter(t => !SYS_TEAMS.has(normN(t.name))), dst.filter(t => !SYS_TEAMS.has(normN(t.name))), 'Team');\n      tick('teams');\n    }\n\n    // ── Role Groups ────────────────────────────────────────────────────────\n    if (scopes.includes('roleGroups')) {\n      logHead('Role Groups');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/users/v1/role_groups/'), fetchAll(dstH, '/API/users/v1/role_groups/')]);\n      compareByName(src, dst, 'Role Group');\n      tick('roleGroups');\n    }\n\n    // ── Metadata Fields ────────────────────────────────────────────────────\n    if (scopes.includes('metadata')) {\n      logHead('Metadata Fields');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/metadata/v1/fields/'), fetchAll(dstH, '/API/metadata/v1/fields/')]);\n      compareByName(src, dst, 'Metadata field', { caseSensitive: true });\n      // Détecter doublons de casse en source\n      const seen = {};\n      src.forEach(f => {\n        const k = normN(f.name || '');\n        if (seen[k] && seen[k] !== f.name) logDiff('Doublon de casse en source : \"' + seen[k] + '\" et \"' + f.name + '\"');\n        seen[k] = f.name;\n      });\n      tick('metadata');\n    }\n\n    // ── Metadata Views ─────────────────────────────────────────────────────\n    if (scopes.includes('metadataViews')) {\n      logHead('Metadata Views');\n      const [srcV, dstV] = await Promise.all([fetchAll(srcH, '/API/metadata/v1/views/'), fetchAll(dstH, '/API/metadata/v1/views/')]);\n      const srcF = srcV.filter(v => !SYS_MDVS.has(normN(v.name)));\n      const dstF = dstV.filter(v => !SYS_MDVS.has(normN(v.name)));\n      const { missing } = compareByName(srcF, dstF, 'MD View');\n      if (!missing) {\n        const dstByName = {};\n        dstF.forEach(v => { dstByName[normN(v.name)] = v; });\n        let mismatch = 0;\n        for (const sv of srcF) {\n          const dv = dstByName[normN(sv.name)];\n          if (!dv) continue;\n          const [sd, dd] = await Promise.all([\n            apiFetch(srcH, '/API/metadata/v1/views/' + sv.id + '/'),\n            apiFetch(dstH, '/API/metadata/v1/views/' + dv.id + '/'),\n          ]);\n          const sf = (sd?.view_fields || []).map(f => normN(f.name || f.field_name || '')).filter(Boolean).sort().join(',');\n          const df = (dd?.view_fields || []).map(f => normN(f.name || f.field_name || '')).filter(Boolean).sort().join(',');\n          if (sf !== df) {\n            const sfSet = new Set(sf.split(',').filter(Boolean));\n            const dfSet = new Set(df.split(',').filter(Boolean));\n            const mf = [...sfSet].filter(f => !dfSet.has(f));\n            const ef = [...dfSet].filter(f => !sfSet.has(f));\n            logDiff('MD View \"' + sv.name + '\"' + (mf.length ? ' — manquants: ' + mf.join(', ') : '') + (ef.length ? ' — en trop: ' + ef.join(', ') : ''));\n            mismatch++;\n          }\n        }\n        if (!mismatch && srcF.length) logOk('Champs de toutes les MD Views conformes');\n      }\n      // ACLs MD Views (si activé)\n      if (checkAcls) {\n        const dstVByName = {};\n        dstF.forEach(v => { if (v.name) dstVByName[normN(v.name)] = v; });\n        let aclDiff = 0, aclChk = 0;\n        for (const sv of srcF) {\n          const dv = dstVByName[normN(sv.name)];\n          if (!dv) continue;\n          const [sa, da] = await Promise.all([\n            apiFetch(srcH, '/API/acls/v1/acl/metadata_views/' + sv.id + '/'),\n            apiFetch(dstH, '/API/acls/v1/acl/metadata_views/' + dv.id + '/'),\n          ]);\n          if (!sa || !da) continue;\n          const sc2 = (sa.groups_acl||[]).length, dc2 = (da.groups_acl||[]).length;\n          if (sc2 !== dc2) { logDiff('ACL MD View \"' + sv.name + '\" : src=' + sc2 + ' groupe(s), dst=' + dc2); aclDiff++; }\n          aclChk++;\n        }\n        if (!aclDiff && aclChk) logOk('ACLs MD Views : ' + aclChk + ' vérifiée(s), conformes en nombre');\n      }\n      tick('metadataViews');\n    }\n\n    // ── Saved Searches ─────────────────────────────────────────────────────\n    if (scopes.includes('savedSearches')) {\n      logHead('Saved Searches');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/search/v1/search/saved/'), fetchAll(dstH, '/API/search/v1/search/saved/')]);\n      const { missing: ssMissing, srcMap: ssMap, dstMap: dstSSMap2 } = compareByName(src, dst, 'Saved Search');\n      // ACLs Saved Searches (si activé)\n      if (checkAcls && !ssMissing) {\n        const dstSSByName2 = {};\n        dst.forEach(s => { if (s.name) dstSSByName2[normN(s.name)] = s; });\n        let aclDiff = 0, aclChk = 0;\n        for (const ss of src) {\n          const ds = dstSSByName2[normN(ss.name)];\n          if (!ds) continue;\n          const [sa, da] = await Promise.all([\n            apiFetch(srcH, '/API/acls/v1/acl/saved_searches/' + ss.id + '/'),\n            apiFetch(dstH, '/API/acls/v1/acl/saved_searches/' + ds.id + '/'),\n          ]);\n          if (!sa || !da) continue;\n          const sc2 = (sa.groups_acl||[]).length, dc2 = (da.groups_acl||[]).length;\n          if (sc2 !== dc2) { logDiff('ACL Saved Search \"' + ss.name + '\" : src=' + sc2 + ' groupe(s), dst=' + dc2); aclDiff++; }\n          aclChk++;\n        }\n        if (!aclDiff && aclChk) logOk('ACLs Saved Searches : ' + aclChk + ' vérifiée(s), conformes en nombre');\n      }\n      tick('savedSearches');\n    }\n\n    // ── Custom Actions ─────────────────────────────────────────────────────\n    if (scopes.includes('customActions')) {\n      logHead('Custom Actions');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/assets/v1/custom_actions/'), fetchAll(dstH, '/API/assets/v1/custom_actions/')]);\n      const srcCAm = src.map(o => ({...o, name: o.title||o.name}));\n      const dstCAm = dst.map(o => ({...o, name: o.title||o.name}));\n      const { missing: caMissing } = compareByName(srcCAm, dstCAm, 'Custom Action');\n      // ACLs Custom Actions (si activé)\n      if (checkAcls && !caMissing) {\n        const dstCAByName = {};\n        dst.forEach(a => { const k = normN(a.title||a.name||''); if (k) dstCAByName[k] = a; });\n        let aclDiff = 0, aclChk = 0;\n        for (const ca of src) {\n          const da = dstCAByName[normN(ca.title||ca.name||'')];\n          if (!da) continue;\n          const [sa, da2] = await Promise.all([\n            apiFetch(srcH, '/API/acls/v1/acl/custom_actions/' + ca.id + '/'),\n            apiFetch(dstH, '/API/acls/v1/acl/custom_actions/' + da.id + '/'),\n          ]);\n          if (!sa || !da2) continue;\n          const sc2 = (sa.groups_acl||[]).length, dc2 = (da2.groups_acl||[]).length;\n          if (sc2 !== dc2) { logDiff('ACL Custom Action \"' + (ca.title||ca.name) + '\" : src=' + sc2 + ' groupe(s), dst=' + dc2); aclDiff++; }\n          aclChk++;\n        }\n        if (!aclDiff && aclChk) logOk('ACLs Custom Actions : ' + aclChk + ' vérifiée(s), conformes en nombre');\n      }\n      tick('customActions');\n    }\n\n    // ── Webhooks ───────────────────────────────────────────────────────────\n    if (scopes.includes('webhooks')) {\n      logHead('Webhooks');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/notifications/v1/webhooks/'), fetchAll(dstH, '/API/notifications/v1/webhooks/')]);\n      const { missing } = compareByName(src, dst, 'Webhook');\n      if (!missing) {\n        const dstByName = {};\n        dst.forEach(w => { if (w.name) dstByName[normN(w.name)] = w; });\n        let diff = 0;\n        src.forEach(sw => {\n          const dw = dstByName[normN(sw.name)];\n          if (!dw) return;\n          const d = [];\n          if (sw.url !== dw.url) d.push('url');\n          if (sw.event_type !== dw.event_type) d.push('event_type');\n          if (sw.realm !== dw.realm) d.push('realm');\n          if (sw.operation !== dw.operation) d.push('operation');\n          if (d.length) { logDiff('Webhook \"' + sw.name + '\" diverge : ' + d.join(', ')); diff++; }\n        });\n        if (!diff && src.length) logOk('Paramètres des webhooks conformes');\n      }\n      tick('webhooks');\n    }\n\n    // ── Automations ────────────────────────────────────────────────────────\n    if (scopes.includes('automations')) {\n      logHead('Automations');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/automations/v1/automations/'), fetchAll(dstH, '/API/automations/v1/automations/')]);\n      const srcA = src.filter(a => String(a.status||'').toUpperCase() === 'ACTIVE');\n      const dstAll = {};\n      dst.forEach(a => { if (a.name) dstAll[normN(a.name)] = a; });\n      let missing = 0, inactive = 0;\n      srcA.forEach(sa => {\n        const da = dstAll[normN(sa.name)];\n        if (!da) { logMiss('Automation manquante en dst : ' + sa.name); missing++; }\n        else if (String(da.status||'').toUpperCase() !== 'ACTIVE') { logInfo('Automation \"' + sa.name + '\" désactivée en dst (intentionnel)'); inactive++; }\n      });\n      if (!missing) {\n        if (inactive) logOk('Automations présentes (' + inactive + ' désactivée(s) en dst — intentionnel)');\n        else if (srcA.length) logOk('Automations actives : ' + srcA.length + ' conformes');\n        else logInfo('Aucune automation active en source');\n      }\n      tick('automations');\n    }\n\n    // ── Relation Types ─────────────────────────────────────────────────────\n    if (scopes.includes('relationTypes')) {\n      logHead('Relation Types');\n      const [src, dst] = await Promise.all([fetchAll(srcH, '/API/assets/v1/assets/relation_types/'), fetchAll(dstH, '/API/assets/v1/assets/relation_types/')]);\n      compareByName(src.filter(r => !r.is_system), dst.filter(r => !r.is_system), 'Relation Type');\n      tick('relationTypes');\n    }\n\n    // ── Categories ─────────────────────────────────────────────────────────\n    if (scopes.includes('categories')) {\n      logHead('Catégories');\n      const SYS_CATS = new Set(['default', 'generic', 'tag']);\n      const OBJ_TYPES = ['assets', 'collections', 'segments', 'custom_actions'];\n      const srcCats = new Map(), dstCats = new Map();\n      for (const t of OBJ_TYPES) {\n        const [sr, dr] = await Promise.all([\n          apiFetch(srcH, '/API/metadata/v1/' + t + '/categories/?per_page=500'),\n          apiFetch(dstH, '/API/metadata/v1/' + t + '/categories/?per_page=500'),\n        ]);\n        (sr?.objects || []).forEach(c => { const k = normN(c.name); if (!SYS_CATS.has(k)) srcCats.set(k, c); });\n        (dr?.objects || []).forEach(c => { const k = normN(c.name); if (!SYS_CATS.has(k)) dstCats.set(k, c); });\n      }\n      let missing = 0, extra = 0;\n      srcCats.forEach((c, k) => { if (!dstCats.has(k)) { logMiss('Catégorie manquante en dst : ' + (c.name || k)); missing++; } });\n      dstCats.forEach((c, k) => { if (!srcCats.has(k)) { logDiff('Catégorie présente en dst uniquement : ' + (c.name || k)); extra++; } });\n      if (!missing && !extra) logOk('Catégories : ' + srcCats.size + ' conformes');\n      tick('categories');\n    }\n\n    // ── Share Settings ─────────────────────────────────────────────────────\n    if (scopes.includes('systemSettings')) {\n      logHead('Share Settings');\n      const KEYS = ['default_share_options','share_expiration_time','external_share',\n        'allow_invites_by_link','search_in_transcriptions','collections_get_parent_acls',\n        'append_asset_uuid_to_downloads','use_asset_name_on_download'];\n      const [sr, dr] = await Promise.all([\n        apiFetch(srcH, '/API/settings/v1/merged/current/'),\n        apiFetch(dstH, '/API/settings/v1/merged/current/'),\n      ]);\n      if (!sr || !dr) { logDiff('Impossible de lire les settings'); }\n      else {\n        let diff = 0;\n        KEYS.forEach(k => {\n          const sv = JSON.stringify(sr[k] ?? null);\n          const dv = JSON.stringify(dr[k] ?? null);\n          if (sv !== dv) { logDiff('Share Settings \"' + k + '\" diverge'); diff++; }\n        });\n        if (!diff) logOk('Share Settings conformes');\n      }\n      tick('systemSettings');\n    }\n\n    // ── Collections ────────────────────────────────────────────────────────\n    if (scopes.includes('collections')) {\n      logHead('Collections' + (checkAcls ? ' + ACLs' : ''));\n      // Récupération via Search API (comme la sync)\n      async function fetchAllCols(headers, label) {\n        const out = [], per = 150;\n        let page = 1;\n        const h = Object.assign({}, headers, {'Content-Type':'application/json'});\n        while (true) {\n          const r = await fetch('/API/search/v1/search/?per_page=' + per + '&page=' + page, {\n            method: 'POST', headers: h, body: JSON.stringify({doc_types: ['collections']})\n          }).catch(() => null);\n          if (!r || !r.ok) break;\n          const j = await r.json().catch(() => ({}));\n          const objs = (j.objects || []).filter(c => (!c.status || c.status === 'ACTIVE') && !c.date_deleted);\n          if (!j.objects?.length) break;\n          out.push(...objs);\n          if ((j.pages || 0) && page >= j.pages) break;\n          if (!j.pages && objs.length < per) break;\n          page++;\n          if (page > 500) break;\n        }\n        return out;\n      }\n\n      const [srcCols, dstCols] = await Promise.all([\n        fetchAllCols(srcH, 'SRC'), fetchAllCols(dstH, 'DST')\n      ]);\n\n      // Index par titre (lowercase) pour comparaison rapide\n      const srcByTitle = new Map(), dstByTitle = new Map();\n      srcCols.forEach(c => { const k = normN(c.title||c.name||''); if (k) srcByTitle.set(k, c); });\n      dstCols.forEach(c => { const k = normN(c.title||c.name||''); if (k) dstByTitle.set(k, c); });\n\n      let missing = 0, extra = 0;\n      srcByTitle.forEach((c, k) => { if (!dstByTitle.has(k)) { logMiss('Collection manquante en dst : ' + (c.title||c.name||k)); missing++; } });\n      dstByTitle.forEach((c, k) => { if (!srcByTitle.has(k)) { logDiff('Collection présente en dst uniquement : ' + (c.title||c.name||k)); extra++; } });\n      if (!missing && !extra) logOk('Collections : ' + srcByTitle.size + ' présentes des deux côtés');\n      else if (missing) logDiff(missing + ' collection(s) manquante(s) — une sync est recommandée');\n\n      // ACLs collections (si activé)\n      if (checkAcls && !missing) {\n        let aclDiff = 0, aclChecked = 0;\n        const srcList = [...srcByTitle.values()];\n        for (let i = 0; i < srcList.length; i++) {\n          const sc = srcList[i];\n          const dc = dstByTitle.get(normN(sc.title||sc.name||''));\n          if (!dc) continue;\n          if (i % 50 === 0) setProgress(5 + Math.round(((doneW + (i/srcList.length)*WEIGHT.collections) / totalW) * 90), 'ACLs collections ' + i + '/' + srcList.length + '…');\n          const [sa, da] = await Promise.all([\n            apiFetch(srcH, '/API/acls/v1/acl/collections/' + sc.id + '/'),\n            apiFetch(dstH, '/API/acls/v1/acl/collections/' + dc.id + '/'),\n          ]);\n          if (!sa || !da) continue;\n          const sGroups = new Set((sa.groups_acl||[]).map(g => g.group_id));\n          const dGroups = new Set((da.groups_acl||[]).map(g => g.group_id + ''));\n          // Comparer par group_id ne fonctionne pas inter-domaines (IDs différents)\n          // On compare le nombre de groupes comme indicateur\n          const sCnt = (sa.groups_acl||[]).length + (sa.propagating_groups_acl||[]).length;\n          const dCnt = (da.groups_acl||[]).length + (da.propagating_groups_acl||[]).length;\n          if (sCnt !== dCnt) {\n            logDiff('ACL collection \"' + (sc.title||sc.name) + '\" : src=' + sCnt + ' groupe(s), dst=' + dCnt);\n            aclDiff++;\n          }\n          aclChecked++;\n        }\n        if (!aclDiff && aclChecked) logOk('ACLs collections : ' + aclChecked + ' vérifiées, conformes en nombre');\n        else if (aclDiff) logDiff(aclDiff + ' collection(s) avec ACLs divergentes (nombre de groupes)');\n      }\n      tick('collections');\n    }\n\n    // ── Export Locations ───────────────────────────────────────────────────\n    if (scopes.includes('exportLocations')) {\n      logHead('Export Locations');\n      const [src, dst] = await Promise.all([\n        fetchAll(srcH, '/API/files/v1/export_locations/'),\n        fetchAll(dstH, '/API/files/v1/export_locations/'),\n      ]);\n      const { missing, srcMap, dstMap } = compareByName(src, dst, 'Export Location');\n\n      // Paramètres des export locations communes\n      if (!missing) {\n        const dstByName = {};\n        dst.forEach(e => { if (e.name) dstByName[normN(e.name)] = e; });\n        let paramDiff = 0;\n        src.forEach(se => {\n          const de = dstByName[normN(se.name)];\n          if (!de) return;\n          const d = [];\n          if ((se.path || '') !== (de.path || '')) d.push('path: \"' + (se.path||'') + '\" → \"' + (de.path||'') + '\"');\n          if ((se.export_original) !== (de.export_original)) d.push('export_original');\n          if ((se.export_proxy) !== (de.export_proxy)) d.push('export_proxy');\n          if (d.length) { logDiff('Export Location \"' + se.name + '\" diverge : ' + d.join(', ')); paramDiff++; }\n        });\n        if (!paramDiff && src.length) logOk('Paramètres des Export Locations conformes');\n      }\n\n      // ACLs export locations (si activé)\n      if (checkAcls) {\n        const dstById = {};\n        dst.forEach(e => { if (e.name) dstById[normN(e.name)] = e; });\n        let aclDiff = 0, aclChecked = 0;\n        for (const se of src) {\n          const de = dstById[normN(se.name)];\n          if (!de) continue;\n          const [sa, da] = await Promise.all([\n            apiFetch(srcH, '/API/acls/v1/acl/export_locations/' + se.id + '/'),\n            apiFetch(dstH, '/API/acls/v1/acl/export_locations/' + de.id + '/'),\n          ]);\n          if (!sa || !da) continue;\n          const sCnt = (sa.groups_acl||[]).length + (sa.users_acl||[]).length;\n          const dCnt = (da.groups_acl||[]).length + (da.users_acl||[]).length;\n          if (sCnt !== dCnt) { logDiff('ACL Export Location \"' + se.name + '\" : src=' + sCnt + ', dst=' + dCnt); aclDiff++; }\n          aclChecked++;\n        }\n        if (!aclDiff && aclChecked) logOk('ACLs Export Locations : ' + aclChecked + ' vérifiée(s), conformes en nombre');\n        else if (aclDiff) logDiff(aclDiff + ' Export Location(s) avec ACLs divergentes');\n      }\n      tick('exportLocations');\n    }\n\n    // ── Résumé ────────────────────────────────────────────────────────────\n    setProgress(100, 'Mirror Check terminé');\n    addCLog('', 'l-info');\n    addCLog('══ Résumé', 'l-check-head');\n    addCLog('  ✅ Conformes : ' + okC, 'l-check-ok');\n    if (warnC) addCLog('  ⚠️ Divergences : ' + warnC, 'l-check-diff');\n    if (errC)  addCLog('  ❌ Manquants   : ' + errC,  'l-check-miss');\n\n    const b = document.getElementById('result-banner');\n    if (errC > 0) {\n      b.className = 'result-banner err';\n      document.getElementById('result-icon').textContent = '❌';\n      document.getElementById('result-text').textContent = errC + ' élément(s) manquant(s) — sync recommandée.';\n    } else if (warnC > 0) {\n      b.className = 'result-banner err';\n      document.getElementById('result-icon').textContent = '⚠️';\n      document.getElementById('result-text').textContent = warnC + ' divergence(s) détectée(s) — vérifiez le journal.';\n    } else {\n      b.className = 'result-banner ok';\n      document.getElementById('result-icon').textContent = '✅';\n      document.getElementById('result-text').textContent = 'Environnements conformes.';\n    }\n    b.style.display = 'flex';\n\n  } catch(e) {\n    addCLog('❌ Erreur Mirror Check : ' + e.message, 'l-err');\n    setProgress(100, 'Erreur');\n  }\n\n  document.getElementById('btn-run').disabled    = false;\n  document.getElementById('btn-mirror').disabled = false;\n}\n\n// ── Vérification nom du token (PROD/DEV croisé) ───────────────────────────────\nconst _tcTimers = {};\nconst _tcCache  = {};  // \"appid|token\" → { name, ts }\n\nfunction scheduleTokenCheck(env) {\n  clearTimeout(_tcTimers[env]);\n  setEl(env + '-token-check', '');\n  _tcTimers[env] = setTimeout(() => checkToken(env), 800);\n}\n\nfunction setEl(id, html) {\n  const el = document.getElementById(id);\n  if (el) el.innerHTML = html;\n}\n\nasync function checkToken(env) {\n  const appId = document.getElementById(env + '-appid').value.trim();\n  const token = document.getElementById(env + '-token').value.trim();\n  const checkEl = env + '-token-check';\n\n  if (!appId || !token) { setEl(checkEl, ''); return; }\n\n  const cacheKey = appId + '|' + token;\n  const cached   = _tcCache[cacheKey];\n  if (cached && Date.now() - cached.ts < 60000) {\n    renderTokenResult(env, cached.name);\n    return;\n  }\n\n  setEl(checkEl, '<span class=\"tc-spin\">⏳ Vérification…</span>');\n\n  try {\n    const url  = document.getElementById(env + '-url').value.trim() || 'https://app.iconik.io';\n    const resp = await fetch('/API/auth/v1/apps/' + encodeURIComponent(appId) + '/', {\n      headers: { 'App-ID': appId, 'Auth-Token': token }\n    });\n    if (!resp.ok) {\n      setEl(checkEl, '<span class=\"tc-err\">❌ Credentials invalides (HTTP ' + resp.status + ')</span>');\n      return;\n    }\n    const data = await resp.json();\n    const name = data.name || data.title || '';\n    _tcCache[cacheKey] = { name, ts: Date.now() };\n    renderTokenResult(env, name);\n  } catch (e) {\n    setEl(checkEl, '<span class=\"tc-err\">❌ Erreur réseau</span>');\n  }\n}\n\nfunction renderTokenResult(env, name) {\n  const checkEl = env + '-token-check';\n  if (!name) { setEl(checkEl, '<span class=\"tc-warn\">⚠️ Nom introuvable</span>'); return; }\n\n  const nameUp  = name.toUpperCase();\n  const hasProd = nameUp.includes('PROD');\n  const hasDev  = nameUp.includes('DEV') || nameUp.includes('STAGING');\n\n  let cls = 'tc-ok', icon = '✅', msg = name;\n\n  if (env === 'prod' && hasDev && !hasProd) {\n    cls = 'tc-warn'; icon = '⚠️';\n    msg = name + ' — ATTENTION : token DEV dans le champ PROD !';\n  } else if (env === 'dev' && hasProd && !hasDev) {\n    cls = 'tc-warn'; icon = '⚠️';\n    msg = name + ' — ATTENTION : token PROD dans le champ DEV !';\n  } else if (env === 'prod' && !hasProd && !hasDev) {\n    cls = 'tc-ok'; icon = '✅';\n    msg = name + ' (non classifié)';\n  } else if (env === 'dev' && !hasProd && !hasDev) {\n    cls = 'tc-ok'; icon = '✅';\n    msg = name + ' (non classifié)';\n  }\n\n  setEl(checkEl, `<span class=\"${cls}\">${icon} ${msg}</span>`);\n}\n\n// Bloquer le lancement si croisement détecté\nfunction hasTokenWarning() {\n  const prodEl = document.getElementById('prod-token-check');\n  const devEl  = document.getElementById('dev-token-check');\n  return (prodEl && prodEl.querySelector('.tc-warn')) ||\n         (devEl  && devEl.querySelector('.tc-warn'));\n}\n</script>\n</body>\n</html>\n",
  "sync_dd.js": "#!/usr/bin/env node\n// =============================================================================\n// Iconik Sync DD — Autonome (Node.js)\n// Logique extraite directement de script-sync.js (APS Askida)\n// Aucune dépendance npm — stdlib Node.js uniquement\n//\n// Usage :\n//   node sync_dd.js --src-appid X --src-token Y --dst-appid Z --dst-token W\n//                   [--mode add_update|add_only|overwrite]\n//                   [--scopes teams,collections,...]\n//                   [--include-sys-teams]\n//                   [--dry-run]\n// =============================================================================\n\n'use strict';\n\nconst https   = require('https');\nconst http    = require('http');\nconst { URL } = require('url');\n\n// ── Logger ────────────────────────────────────────────────────────────────────\nfunction log(msg) {\n  const ts = new Date().toLocaleTimeString('fr-FR');\n  const line = '[' + ts + '] ' + String(msg);\n  process.stdout.write(line + '\\n');\n  // Alimenter le tableau de log pour --json-output\n  if (global._syncLogLines) global._syncLogLines.push(line);\n}\n\n// ── fetch() compatible browser API ───────────────────────────────────────────\nfunction fetch(url, opts) {\n  opts = opts || {};\n  return new Promise((resolve, reject) => {\n    let parsed;\n    try { parsed = new URL(url); } catch(e) { return reject(e); }\n    const lib  = parsed.protocol === 'https:' ? https : http;\n    const body = opts.body ? Buffer.from(opts.body, 'utf-8') : null;\n    const reqOpts = {\n      hostname: parsed.hostname,\n      port:     parsed.port || (parsed.protocol === 'https:' ? 443 : 80),\n      path:     parsed.pathname + parsed.search,\n      method:   opts.method || 'GET',\n      headers:  Object.assign({ 'Content-Type': 'application/json' }, opts.headers || {}),\n    };\n    if (body) reqOpts.headers['Content-Length'] = body.length;\n    const req = lib.request(reqOpts, (res) => {\n      const chunks = [];\n      res.on('data', c => chunks.push(c));\n      res.on('end', () => {\n        const raw = Buffer.concat(chunks).toString('utf-8');\n        resolve({\n          ok:     res.statusCode >= 200 && res.statusCode < 300,\n          status: res.statusCode,\n          json:   () => Promise.resolve(JSON.parse(raw || '{}')),\n          text:   () => Promise.resolve(raw),\n        });\n      });\n    });\n    req.on('error', reject);\n    if (body) req.write(body);\n    req.end();\n  });\n}\n\n// ── Stubs DOM / APS ───────────────────────────────────────────────────────────\nconst WFD_SYSTEM_TEAM_NAMES = ['everyone', 'administrator'];\nfunction wfdNormName(s) { return String(s || '').trim().toLowerCase(); }\nfunction isSystemTeam(nameOrObj) {\n  const name = typeof nameOrObj === 'string' ? nameOrObj : (nameOrObj?.nom || nameOrObj?.name || '');\n  return WFD_SYSTEM_TEAM_NAMES.includes(wfdNormName(name));\n}\n\n\n// ── Variables globales APS utilisées comme stockage inter-fonctions ──────────\nlet __wfd_dd_acl_unresolved       = [];\nlet __wfd_dd_team_settings_stats  = null;\n\n// ── Stubs fonctions APS optionnelles ─────────────────────────────────────────\n// Ces fonctions contrôlent des options UI dans APS — on les remplace par des\n// valeurs fixes raisonnables pour le mode standalone.\nfunction wfdIncludeSystemCategories()     { return false; }\nfunction wfdIncludeSystemMetadataViews()  { return false; }\nfunction wfdIsSystemMetadataView(name)    {\n  return ['segment tags', 'tutorials'].includes((name || '').toLowerCase().trim());\n}\nfunction wfdIncludeSystemTeams()          { return cfg && cfg.includeSysTeams ? true : false; }\n\n// ── Utilitaires extraits de script-sync.js ───────────────────────────────────\n\n\n\nasync function fetchAllPages(base, headers, endpoint, mapFn) {\n  let page = 1;\n  const perPage = 500;\n  const out = [];\n  let ep = String(endpoint || '');\n  const hasPer = /(^|[?&])per_page=/.test(ep);\n  const hasPage = /(^|[?&])page=/.test(ep);\n\n  while (true) {\n    let url = ep;\n    const join = url.includes('?') ? '&' : '?';\n    if (!hasPer) url += join + 'per_page=' + perPage;\n    if (!hasPage) url += (url.includes('?') ? '&' : '?') + 'page=' + page;\n\n    const r = await fetch(base + url, { headers }).catch(() => null);\n    if (!r || !r.ok) break;\n\n    const j = await r.json().catch(() => ({}));\n    const items = j.objects || j.results || [];\n    if (!items.length) break;\n\n    out.push(...(mapFn ? items.map(mapFn) : items));\n    if (items.length < perPage) break;\n    page++;\n  }\n  return out;\n}\n\n// =======================================================\n// WFD — Collections helpers (Search is source of truth)\n// =======================================================\nfunction wfdColTitle(o){\n  return String((o && (o.title || o.name || o.nom)) || '').trim();\n}\nfunction wfdColParentId(o){\n  const pid = o && o.parent_id ? String(o.parent_id) : '';\n  if (pid) return pid;\n  const inc = o && Array.isArray(o.in_collections) ? o.in_collections : [];\n  return inc && inc.length ? String(inc[0]) : null;\n}\n\n\nasync function wfdFetchAllCollectionsSearch(base, headers, label){\n  const out = [];\n  const per = 150;\n  let page = 1;\n  const h = Object.assign({}, headers, { 'Content-Type': 'application/json' });\n  const tag = label || (base.includes('app.iconik') ? 'collections' : 'collections');\n  while (true) {\n    const url = base + '/API/search/v1/search/?per_page=' + per + '&page=' + page;\n    const r = await fetch(url, {\n      method: 'POST',\n      headers: h,\n      body: JSON.stringify({ doc_types: ['collections'] })\n    }).catch(() => null);\n    if (!r || !r.ok) break;\n    const j = await r.json().catch(() => ({}));\n    const objs = (j.objects || []).filter(c =>\n      (!c.status || c.status === 'ACTIVE') && !c.date_deleted\n    );\n    if (!j.objects?.length) break;\n    out.push(...objs);\n    const pages = j.pages || 0;\n    if (pages > 1) log('  ' + tag + ' — page ' + page + '/' + pages + ' (' + out.length + ' trouvées)');\n    if (pages && page >= pages) break;\n    if (!pages && objs.length < per) break;\n    page++;\n    if (page > 500) break; // guard\n  }\n  return out;\n}\n\n// =======================================================\n// WFD — Collections hydration (fallback when Search omits parent_id)\n// =======================================================\n\n\nasync function wfdHydrateCollectionsDetails(base, headers, ids, opts){\n  opts = opts || {};\n  const concurrency = opts.concurrency || 10;\n  const label       = opts.label || 'Hydratation collections';\n  const delay = (ms) => new Promise(r => setTimeout(r, ms));\n  const out = {};\n  const total = (ids || []).length;\n  const queue = (ids || []).slice();\n  let done = 0;\n\n  async function worker(){\n    while(queue.length){\n      const id = queue.shift();\n      if(!id) continue;\n      // retry up to 3\n      let last = null;\n      for(let attempt=1; attempt<=3; attempt++){\n        const r = await fetch(base + '/API/assets/v1/collections/' + encodeURIComponent(id) + '/', { headers: headers }).catch(() => null);\n        last = r;\n        if(r && r.ok){\n          const j = await r.json().catch(() => null);\n          if(j && j.id){ out[String(j.id)] = j; }\n          break;\n        }\n        await delay(200 * attempt);\n      }\n      done++;\n      if (total > 0 && done % 50 === 0) {\n        log('  ' + label + ' : ' + done + '/' + total);\n      }\n    }\n  }\n\n  if (total > 0) log('  ' + label + ' : 0/' + total);\n  const workers = [];\n  for(let i=0;i<concurrency;i++) workers.push(worker());\n  await Promise.all(workers);\n  log('  ' + label + ' : ' + total + '/' + total + ' ✓');\n  return out;\n}\n\n\n\n\nasync function applySyncMode(mode, srcItems, dstItems, base, headers, ep, bodyFn, keyFn, opts={}) {\n  // keyFn(item) → clé de comparaison (nom normalisé)\n  if (!keyFn) keyFn = o => (o.name || o.title || o.nom || '').toLowerCase();\n  if (!bodyFn) bodyFn = o => o;\n\n  const dstMap = {};\n  const _pickId = (o) =>\n    (o && (o.id || o.uuid || o.field_id || o.webhook_id || o.search_id || o.action_id || o._id || o.name || o.field_name)) || null;\n\n  (dstItems || []).forEach(o => {\n    const k = keyFn(o);\n    if (k) dstMap[k] = o;\n  });\n\n  const srcKeys = new Set((srcItems || []).map(o => keyFn(o)));\n\n  let created = 0, updated = 0, deleted = 0, failed = 0;\n  const failures = {}; // status → count\n\n  // ─────────────────────────────────────────────\n  // Helper: log 1 sample per status (anti-spam)\n  // ─────────────────────────────────────────────\n  async function logFailure(r, where, url) {\n    const s = r?.status || 'ERR';\n    failures[s] = (failures[s] || 0) + 1;\n\n    if (!applySyncMode._samples) applySyncMode._samples = {};\n    const key = where + ':' + s;\n\n    if (r && !r.ok && !applySyncMode._samples[key]) {\n      applySyncMode._samples[key] = true;\n      const txt = await r.text().catch(() => '');\n      console.warn(`[applySyncMode][${where}][${s}]`, url, txt.slice(0, 600));\n    }\n  }\n\n  // ─────────────────────────────────────────────\n  // Helper: POST create (returns response json if possible)\n  // ─────────────────────────────────────────────\n  async function doPost(url, body) {\n    const r = await fetch(url, { method: 'POST', headers, body: JSON.stringify(body) }).catch(() => null);\n    if (r?.ok) {\n      created++;\n      const obj = await r.json().catch(() => null);\n      return { ok: true, r, obj };\n    }\n    failed++;\n    if (r) await logFailure(r, 'POST', url);\n    else {\n      failures.ERR = (failures.ERR || 0) + 1;\n      console.warn('[applySyncMode][POST][ERR]', url, '(fetch failed)');\n    }\n    return { ok: false, r, obj: null };\n  }\n\n  // ─────────────────────────────────────────────\n  // Helper: PUT update (fallback to POST on 404)\n  // ─────────────────────────────────────────────\n  async function doPutOrPostFallback(putUrl, postUrl, body, ctx) {\n    const method = opts.usePatch ? 'PATCH' : 'PUT';\n    const r = await fetch(putUrl, { method, headers, body: JSON.stringify(body) }).catch(() => null);\n\n    if (r?.ok) {\n      updated++;\n      return { ok: true, r, did: 'PUT', obj: null };\n    }\n\n    // If 404 => object not found on destination, fallback POST\n    if (r && r.status === 404) {\n      console.warn('[applySyncMode] PUT 404 → fallback POST', { ...ctx, putUrl, postUrl });\n      // note: counts => this becomes a CREATE, not UPDATE\n      failed++; // count the failed PUT as failed attempt\n      await logFailure(r, 'PUT', putUrl);\n\n      const postRes = await doPost(postUrl, body);\n      return { ok: postRes.ok, r: postRes.r, did: 'POST_FALLBACK', obj: postRes.obj };\n    }\n\n    // Other errors: count as failed update\n    failed++;\n    if (r) await logFailure(r, 'PUT', putUrl);\n    else {\n      failures.ERR = (failures.ERR || 0) + 1;\n      console.warn('[applySyncMode][PUT][ERR]', putUrl, '(fetch failed)');\n    }\n    return { ok: false, r, did: 'PUT', obj: null };\n  }\n\n  // Remove query from ep for write endpoints when needed\n  const epWriteBase = ep.replace(/\\?.*$/, ''); // e.g. '/API/assets/v1/custom_actions/'\n\n  // ─────────────────────────────────────────────\n  // UPSERT loop\n  // ─────────────────────────────────────────────\n  for (const src of (srcItems || [])) {\n    const key = keyFn(src);\n    const dst = dstMap[key];\n    const isNew = !dst;\n    const body = bodyFn(src, isNew);\n\n    try {\n      // CREATE (dst missing)\n      if (!dst) {\n        const postUrl = base + epWriteBase; // safe: ensure trailing slash is already in ep\n        const { ok, obj } = await doPost(postUrl, body);\n\n        // If created, refresh dstMap so following operations use destination id\n        if (ok && obj) {\n          dstMap[key] = obj;\n        }\n      }\n      // UPDATE (only for add_update / overwrite)\n      else if (mode === 'add_update' || mode === 'overwrite') {\n        const dstId = _pickId(dst);\n\n        // If we cannot pick a destination id, treat as create\n        if (!dstId) {\n          console.warn('[applySyncMode] dst exists but no dstId → POST', { key, dst });\n          const postUrl = base + epWriteBase;\n          const { ok, obj } = await doPost(postUrl, body);\n          if (ok && obj) dstMap[key] = obj;\n          continue;\n        }\n\n        const putUrl = base + epWriteBase + dstId + '/';\n        const postUrl = base + epWriteBase;\n\n        const ctx = { key, mode, dstId };\n        const res = await doPutOrPostFallback(putUrl, postUrl, body, ctx);\n\n        // If fallback POST created something, refresh dstMap\n        if (res.ok && res.obj) {\n          dstMap[key] = res.obj;\n        }\n      }\n    } catch (e) {\n      failed++;\n      failures.EXCEPTION = (failures.EXCEPTION || 0) + 1;\n      console.error('[WFD][applySyncMode]', e);\n    }\n  }\n\n  // ─────────────────────────────────────────────\n  // DELETE extras (overwrite)\n  // ─────────────────────────────────────────────\n  if (mode === 'overwrite') {\n    for (const dst of (dstItems || [])) {\n      const key = keyFn(dst);\n      if (!srcKeys.has(key)) {\n        const dstId = _pickId(dst);\n        if (!dstId) continue;\n\n        const delUrl = base + epWriteBase + dstId + '/';\n        const r = await fetch(delUrl, { method: 'DELETE', headers }).catch(() => null);\n\n        if (r?.ok) deleted++;\n        else {\n          failed++;\n          if (r) await logFailure(r, 'DELETE', delUrl);\n          else {\n            failures.ERR = (failures.ERR || 0) + 1;\n            console.warn('[applySyncMode][DELETE][ERR]', delUrl, '(fetch failed)');\n          }\n        }\n      }\n    }\n  }\n\n  return { created, updated, deleted, failed, failures };\n}\n\n\n\nasync function lancerDomaineDomaine(cfg) {\n  const src = { iconikUrl: cfg.srcBase, appId: cfg.srcAppId, token: cfg.srcToken };\n  const dst = { iconikUrl: cfg.dstBase, appId: cfg.dstAppId, token: cfg.dstToken };\n  const scopes = cfg.scopes;\n  const mode   = cfg.mode || 'add_update';\n\nconst doAll  = scopes.includes('all');\nconst active = doAll\n  ? ['collections','metadataViews','metadata','teams','roleGroups','savedSearches','storages','categories','webhooks','customActions','automations','relationTypes','systemSettings','exportLocations']\n  : scopes;\n\n  const srcBase = (src.iconikUrl||'https://app.iconik.io').replace(/\\/$/,'');\n  const dstBase = (dst.iconikUrl||'https://app.iconik.io').replace(/\\/$/,'');\n  const srcH = {'App-ID':src.appId,'Auth-Token':src.token,'Content-Type':'application/json'};\n  const dstH = {'App-ID':dst.appId,'Auth-Token':dst.token,'Content-Type':'application/json'};\n\n  // ── Job Manager ──\n  \n  \n\n  // =======================================================\n  // DD — Collections : création parent→enfant + mapping srcId→dstId\n  // (ne supprime pas en overwrite: trop risqué; objectif = complétude)\n  // =======================================================\n  const ddColIdMap = {}; // srcCollectionId -> dstCollectionId\n\n  function _colKey(parentId, name) {\n    return String(parentId || 'root') + '|' + String(name || '').toLowerCase().trim();\n  }\n\n  async function syncCollectionsDD() {\n  const stats = { created: 0, updated: 0, failed: 0, failures: {} };\n\n  // 1) Get IDs via Search (fast), then hydrate via /assets/v1/collections/{id}/ (reliable parent_id)\n  log('── Collections : récupération liste source…');\n  const srcDocs = await wfdFetchAllCollectionsSearch(srcBase, srcH, 'Collections SRC').catch(() => []);\n  log('── Collections : récupération liste destination…');\n  const dstDocs = await wfdFetchAllCollectionsSearch(dstBase, dstH, 'Collections DST').catch(() => []);\n\n  const srcIds = (srcDocs || []).map(d => d && d.id).filter(Boolean);\n  const dstIds = (dstDocs || []).map(d => d && d.id).filter(Boolean);\n\n  log('── Collections : hydratation source (' + srcIds.length + ' items)…');\n  const srcDetailById = await wfdHydrateCollectionsDetails(srcBase, srcH, srcIds, { concurrency: 10, label: 'Hydratation SRC' }).catch(() => ({}));\n  log('── Collections : hydratation destination (' + dstIds.length + ' items)…');\n  const dstDetailById = await wfdHydrateCollectionsDetails(dstBase, dstH, dstIds, { concurrency: 10, label: 'Hydratation DST' }).catch(() => ({}));\n\n  function normFromDetail(j){\n    if(!j || !j.id) return null;\n    return {\n      id: String(j.id),\n      title: String(j.title || j.name || j.nom || '').trim() || String(j.id),\n      parent_id: (function(){ const pid = wfdColParentId(j); return pid ? String(pid) : null; })(),\n      date_deleted: j.date_deleted || null,\n      status: j.status || null,\n      storage_id: j.storage_id ? String(j.storage_id) : null,\n    };\n  }\n\n  const srcCols = Object.values(srcDetailById).map(normFromDetail).filter(c => c && !c.date_deleted);\n  const dstColsAll = Object.values(dstDetailById).map(normFromDetail).filter(Boolean);\n\n  // IMPORTANT: ignore soft-deleted collections on destination so they don't block recreations\n  const dstCols = dstColsAll.filter(c => !c.date_deleted);\n\n  const srcById = {};\n  (srcCols || []).forEach(c => { srcById[c.id] = c; });\n\n  // Build children map from source\n  const children = {};\n  const roots = [];\n  (srcCols || []).forEach(c => {\n    const pid = c.parent_id;\n    if (pid && srcById[pid]) {\n      if (!children[pid]) children[pid] = [];\n      children[pid].push(c.id);\n    } else {\n      roots.push(c.id);\n    }\n  });\n\n  // Topo order\n  const topo = [];\n  const walk = (id) => {\n    topo.push(id);\n    (children[id] || []).forEach(walk);\n  };\n  roots.forEach(walk);\n\n  // --- Skip Storage-mapped collections (identified by storage_id) ---\n  // We skip the whole subtree to avoid orphan children being recreated at root.\n  const mappedIds = (srcCols || []).filter(c => c && c.storage_id).map(c => c.id);\n  const skip = new Set();\n  const markSubtree = (id) => {\n    if(!id || skip.has(id)) return;\n    skip.add(id);\n    (children[id] || []).forEach(markSubtree);\n  };\n  mappedIds.forEach(markSubtree);\n  const topoFiltered = topo.filter(id => !skip.has(id));\n\n  const key = (parentId, title) => String(parentId || 'root') + '|' + String(title || '').toLowerCase().trim();\n\n  // Destination index (par parent_id dst + title)\n  const dstByKey = {};\n  (dstCols || []).forEach(c => { dstByKey[key(c.parent_id, c.title)] = c; });\n\n  // ── Pré-remplissage ddColIdMap ───────────────────────────────────────────\n  // Pour les collections qui existent déjà des deux côtés, on construit le\n  // mapping srcId → dstId AVANT la boucle topo, en traversant l'arbo src\n  // en ordre topologique et en résolvant côté dst par chemin complet.\n  // Sans ça, les collections pré-existantes dont le titre est en doublon\n  // n'ont jamais d'entrée ddColIdMap → leurs ACLs sont ignorées.\n  {\n    // Index dst par id pour retrouver parent_id dst d'un nœud déjà mappé\n    const dstById = {};\n    (dstCols || []).forEach(c => { dstById[String(c.id)] = c; });\n\n    for (const srcId of topo) {\n      const s = srcById[srcId];\n      if (!s || skip.has(srcId)) continue;\n      if (ddColIdMap[srcId]) continue; // déjà mappé\n\n      const parentDstId = s.parent_id ? (ddColIdMap[s.parent_id] || null) : null;\n      const k = key(parentDstId, s.title);\n      const existing = dstByKey[k];\n      if (existing) {\n        ddColIdMap[srcId] = String(existing.id);\n      }\n    }\n    const preMapped = Object.keys(ddColIdMap).length;\n    if (preMapped > 0) log('  Collections : ' + preMapped + ' mappages initiaux src→dst');\n  }\n\n  // Retry helper\n  async function bumpFailure(r){\n    const st = r ? r.status : 'ERR';\n    stats.failed++;\n    stats.failures[st] = (stats.failures[st] || 0) + 1;\n  }\n\n  async function createCollection(title){\n    const r = await fetch(dstBase + '/API/assets/v1/collections/', {\n      method: 'POST',\n      headers: dstH,\n      body: JSON.stringify({ title: title })\n    }).catch(() => null);\n    if (r && r.ok) {\n      const obj = await r.json().catch(() => null);\n      stats.created++;\n      return obj;\n    }\n    await bumpFailure(r);\n    return null;\n  }\n\n  async function patchParent(dstId, parentId){\n    for (let attempt = 1; attempt <= 3; attempt++) {\n      const r = await fetch(dstBase + '/API/assets/v1/collections/' + encodeURIComponent(dstId) + '/', {\n        method: 'PATCH',\n        headers: dstH,\n        body: JSON.stringify({ parent_id: parentId })\n      }).catch(() => null);\n      if (r && r.ok) return true;\n      if (attempt === 3) { await bumpFailure(r); return false; }\n      await new Promise(res => setTimeout(res, 250 * attempt));\n    }\n    return false;\n  }\n\n  async function patchTitle(dstId, title){\n    const r = await fetch(dstBase + '/API/assets/v1/collections/' + encodeURIComponent(dstId) + '/', {\n      method: 'PATCH',\n      headers: dstH,\n      body: JSON.stringify({ title: title })\n    }).catch(() => null);\n    if (r && r.ok) { stats.updated++; return true; }\n    await bumpFailure(r);\n    return false;\n  }\n\n  // Main\n  const total = topoFiltered.length;\n  if (total > 0) log('── Collections : sync hiérarchique (' + total + ' items)…');\n\n  // Progress (UI)\n  let done = 0;\n  \n    for (const srcId of topoFiltered) {\n    const s = srcById[srcId];\n    if (!s) continue;\n\n    done++;\n\n        if (done % 25 === 0) {\n          log('  Collections : ' + done + '/' + total);\n          await new Promise(r => setTimeout(r, 0));\n        }\n\n\n    const parentDstId = s.parent_id ? (ddColIdMap[s.parent_id] || null) : null;\n    const k = key(parentDstId, s.title);\n\n    let existing = dstByKey[k];\n\n    if (!existing) {\n      // create as root then move\n      const createdObj = await createCollection(s.title);\n      if (!createdObj || !createdObj.id) continue;\n\n      const newId = String(createdObj.id);\n      ddColIdMap[srcId] = newId;\n\n      if (parentDstId) {\n        await patchParent(newId, parentDstId);\n      }\n\n      dstByKey[k] = { id: newId, title: s.title, parent_id: parentDstId };\n      continue;\n    }\n\n    ddColIdMap[srcId] = existing.id;\n\n    if (mode === 'add_update' || mode === 'overwrite') {\n      if (String(existing.parent_id || '') !== String(parentDstId || '')) {\n        if (parentDstId) {\n          await patchParent(existing.id, parentDstId);\n          existing.parent_id = parentDstId;\n        }\n      }\n      if (String(existing.title || '') !== String(s.title || '')) {\n        await patchTitle(existing.id, s.title);\n        existing.title = s.title;\n      }\n    }\n  }\n\n  {  // post-boucle (reindex)\n    log('── Collections : réindexation destination…');\n\n    // Re-indexer les collections destination pour corriger in_collections et ACL propagation\n    try {\n      \n      const dstColIds = Object.values(ddColIdMap);\n      // Batch de 200 max\n      for (let i = 0; i < dstColIds.length; i += 200) {\n        const batch = dstColIds.slice(i, i + 200);\n        await fetch(dstBase + '/API/assets/v1/reindex/bulk/', {\n          method: 'POST', headers: dstH,\n          body: JSON.stringify({\n            object_ids: batch, object_type: 'collections',\n            realms: ['ACL', 'FORMATS', 'IN_COLLECTIONS'],\n            include_assets: false, include_collections: true, sync_to_another_dc: true\n          })\n        }).catch(() => null);\n      }\n      \n    } catch(e) { console.warn('reindex failed:', e); }\n  }\n\n  stats._srcCols = srcCols;\n    stats._topoFiltered = topoFiltered;\n    stats._srcById = srcById;\n    stats._children = children;\n    stats._roots = roots;\n    return stats;\n}\n\n const EP = {\n    collections  : {r:'/API/assets/v1/collections/',            w:'/API/assets/v1/collections/',   get:r=>r.objects||[], body:o=>({name:o.name,parent_id:o.parent_id||null})},\n    metadataViews: {r:'/API/metadata/v1/views/?per_page=500',       w:'/API/metadata/v1/views/',        get:r=>r.objects||[], body:o=>({name:o.name,description:o.description||''})},\n    metadata     : {r:'/API/metadata/v1/fields/?per_page=500',      w:'/API/metadata/v1/fields/',       get:r=>r.objects||[], body:o=>{\n      const useFacet = (o.use_as_facet===true) || (o.use_in_filters===true);\n      const isBlock  = (o.is_block_field===true) || (o.block_assets===true);\n      const isWarn   = (o.is_warning_field===true) || (o.display_as_warning===true);\n      const multiVal=(o.multi===true)||(o.multiselect===true); const b={name:o.name,label:o.label,description:o.description||'',field_type:o.field_type,options:o.options||[],required:(o.required===true),read_only:(o.read_only===true),hide_if_not_set:(o.hide_if_not_set===true),use_as_facet:useFacet,is_block_field:isBlock,is_warning_field:isWarn,multi:multiVal,multiselect:multiVal}; if (o.min_value!=null) b.min_value=o.min_value; if (o.max_value!=null) b.max_value=o.max_value; if (o.mapped_field_name) b.mapped_field_name=o.mapped_field_name; return b;}},\n    teams        : {r:'/API/users/v1/teams/?per_page=500',         w:'/API/users/v1/teams/',          get:r=>r.objects||[], body:o=>({name:o.name, description:o.description||'', default_user_type:o.default_user_type||'STANDARD', saml_primary_group_priority:o.saml_primary_group_priority||0})},\n    roleGroups   : {r:'/API/users/v1/role_groups/?per_page=500',    w:'/API/users/v1/role_groups/',     get:r=>r.objects||[], body:o=>({name:o.name, roles: o.roles||[], role_categories: o.role_categories||{}})},\n    webhooks     : {r:'/API/notifications/v1/webhooks/?per_page=500',w:'/API/notifications/v1/webhooks/',get:r=>r.objects||[],body:(o,isNew)=>({name:o.name,description:o.description||'',url:o.url,status:'DISABLED',event_type:o.event_type,realm:o.realm,operation:o.operation,query:o.query||'',headers:o.headers||{}})},\n    systemSettings: {r:'/API/settings/v1/merged/current/', w:'/API/settings/v1/system/current/', get:r=>r, body:o=>{\n      const KEYS = ['default_share_options','share_expiration_time','external_share','allow_invites_by_link',\n        'allow_share_magic_link_creation','enforce_magic_link_allowlist','search_users_from_share',\n        'watermark_options','watermark','search_in_transcriptions','collections_get_parent_acls',\n        'lock_mapped_collections','append_asset_uuid_to_downloads','use_asset_name_on_download',\n        'custom_terms','hide_favourites','home_page',\n        'asset_default_sections','search_default_sections','search_display_fields',\n        'required_metadata_views','facet_fields'];\n      const out = {};\n      KEYS.forEach(k => { if (o[k] !== undefined) out[k] = o[k]; });\n      return out;\n    }},\n    relationTypes: {r:'/API/assets/v1/assets/relation_types/?per_page=500', w:'/API/assets/v1/assets/relation_types/', get:r=>(r.objects||[]).filter(o=>!o.is_system), body:o=>({name:o.name,directional:o.is_directional||false,source_label:o.source_label||'',destination_label:o.destination_label||'',description:o.description||''})},\n    customActions: {r:'/API/assets/v1/custom_actions/?per_page=500', w:'/API/assets/v1/custom_actions/', get:r=>r.objects||[], body:(o, isNew, mdvMap)=>{ const b = {title:o.title||o.name,type:o.type||'POST',context:o.context||'ASSET',url:o.url,headers:o.headers||{},disabled:true}; if (o.metadata_view) { const dstMdvId = mdvMap ? mdvMap[o.metadata_view] : null; b.metadata_view = dstMdvId || o.metadata_view; } return b; }, contextEp: true},\n    automations  : {r:'/API/automations/v1/automations/?per_page=500', w:'/API/automations/v1/automations/',get:r=>r.objects||[], body:(o,isNew)=>({name:o.name,status:'INACTIVE',triggers:o.triggers||[],conditions:o.conditions||[],actions:o.actions||[]})},\n    savedSearches: {r:'/API/search/v1/search/saved/?per_page=500',    w:'/API/search/v1/search/saved/',   get:r=>r.objects||[], body:o=>({name:(o.name||o.title||''), criteria:(o.criteria||o.query||o.search_criteria||{})})},\n  };\n\n  const results = [];\n  const orderedActive = (active||[]).slice().sort((a,b)=>({metadata:1,metadataViews:2,collections:0}[a]??10)-({metadata:1,metadataViews:2,collections:0}[b]??10));\n  log('══ Démarrage sync — ' + orderedActive.length + ' scope(s) : ' + orderedActive.join(', '));\n\n  // ── Progress bar globale DD ──\n  let _ddDone = 0;\n  const _ddTotal = orderedActive.length;\n  \n  const _ddProgTick = (label) => {\n    _ddDone++;\n  };\n\n  for (const sc of orderedActive) {\n    log('── ' + sc + '…');\n    // ✅ Collections: création hiérarchique + mapping srcId→dstId\n    if (sc === 'collections') {\n      const r = await syncCollectionsDD();\n      const parts = [];\n      if (r.created) parts.push(r.created + ' créés');\n      if (r.updated) parts.push(r.updated + ' mis à jour');\n      if (r.failed) {\n        const top = Object.entries(r.failures || {}).sort((a,b)=>b[1]-a[1]).slice(0,3)\n          .map(([k,v])=>k+':'+v).join(', ');\n        parts.push(r.failed + ' échecs' + (top ? ' ('+top+')' : ''));\n      }\n      _ddProgTick(sc);\n      results.push('✅ ' + sc + (parts.length ? ' : ' + parts.join(', ') : ''));\n      continue;\n    }\n\n    // ✅ Metadata Views: création avec view_fields requis\n    if (sc === 'metadataViews') {\n      const r = await syncMetadataViewsDD();\n      const parts = [];\n      if (r.created) parts.push(r.created + ' créés');\n      if (r.updated) parts.push(r.updated + ' mis à jour');\n      if (r.failed) {\n        const top = Object.entries(r.failures || {}).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([k,v])=>k+':'+v).join(', ');\n        parts.push(r.failed + ' échecs' + (top ? ' ('+top+')' : ''));\n      }\n      _ddProgTick(sc);\n      results.push('✅ ' + sc + (parts.length ? ' : ' + parts.join(', ') : ''));\n      continue;\n    }\n\n    const def = EP[sc]; if (!def) continue;\n\n    // ✅ Automations DD : résolution metadata_view_id dans actions\n    if (sc === 'automations') {\n      try {\n        // Index vues src→dst\n        const srcAutoViewsR = await fetch(srcBase + '/API/metadata/v1/views/?per_page=500', { headers: srcH }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        const dstAutoViewsR = await fetch(dstBase + '/API/metadata/v1/views/?per_page=500', { headers: dstH }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        const srcAutoViewNameById = {};\n        (srcAutoViewsR.objects||[]).forEach(v=>{ if(v?.id) srcAutoViewNameById[v.id]=v.name; });\n        const dstAutoViewIdByName = {};\n        (dstAutoViewsR.objects||[]).forEach(v=>{ if(v?.name) dstAutoViewIdByName[v.name.toLowerCase().trim()]=v.id; });\n\n        // Index teams src→dst (pour résolution group_ids dans actions ACL)\n        const srcAutoTeamsR = await fetch(srcBase + '/API/users/v1/teams/?per_page=500', { headers: srcH }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        const dstAutoTeamsR = await fetch(dstBase + '/API/users/v1/teams/?per_page=500', { headers: dstH }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        const srcTeamNameById = {};\n        (srcAutoTeamsR.objects||[]).forEach(t=>{ if(t?.id) srcTeamNameById[t.id]=t.name; });\n        const dstTeamIdByName = {};\n        (dstAutoTeamsR.objects||[]).forEach(t=>{ if(t?.name) dstTeamIdByName[t.name.toLowerCase().trim()]=t.id; });\n\n        const resolveGroupId = (srcId) => {\n          const name = srcTeamNameById[srcId];\n          if (!name) return srcId;\n          return dstTeamIdByName[name.toLowerCase().trim()] || srcId;\n        };\n\n        // Helper : résolution des IDs domaine-spécifiques dans parameters\n        // Construire le mapping collections src→dst via recherche (toutes les collections)\n        const fetchAllColIds = async (base, headers) => {\n          const out = {}; let page = 1;\n          while (true) {\n            const r = await fetch(base + '/API/search/v1/search/?per_page=500&page=' + page, {\n              method: 'POST', headers: {...headers, 'Content-Type': 'application/json'},\n              body: JSON.stringify({doc_types: ['collections']})\n            }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n            (r.objects||[]).forEach(c=>{ if(c?.id) out[c.id] = c.title||c.name||''; });\n            if (!r.objects?.length || page >= (r.pages||1) || page > 50) break;\n            page++;\n          }\n          return out;\n        };\n        const srcColNameById = await fetchAllColIds(srcBase, srcH);\n        const dstColsAllR = await fetchAllColIds(dstBase, dstH);\n        const dstColIdByName = {};\n        Object.entries(dstColsAllR).forEach(([id, name]) => {\n          if (name) dstColIdByName[name.toLowerCase().trim()] = id;\n        });\n        const resolveColId = (srcId) => {\n          if (!srcId) return srcId;\n          // D'abord ddColIdMap si disponible\n          if (typeof ddColIdMap !== 'undefined' && ddColIdMap[srcId]) return ddColIdMap[srcId];\n          // Sinon résolution par nom\n          const name = srcColNameById[srcId];\n          if (name) return dstColIdByName[name.toLowerCase().trim()] || srcId;\n          return srcId;\n        };\n\n        const resolveParams = (params) => {\n          const p = {...params};\n          // metadata_view_id → résolution src→dst par nom\n          if (p.metadata_view_id) {\n            const viewName = srcAutoViewNameById[p.metadata_view_id];\n            const dstId = viewName ? dstAutoViewIdByName[viewName.toLowerCase().trim()] : null;\n            if (dstId) p.metadata_view_id = dstId;\n          }\n          // collection_id (singulier)\n          if (p.collection_id) p.collection_id = resolveColId(p.collection_id);\n          // collection_ids (pluriel, tableau)\n          if (Array.isArray(p.collection_ids)) p.collection_ids = p.collection_ids.map(resolveColId);\n          // objects → actions ACL UPDATE_ACL : résolution group_ids\n          if (Array.isArray(p.objects)) {\n            p.objects = p.objects.map(obj => {\n              if (!Array.isArray(obj.group_ids)) return obj;\n              return { ...obj, group_ids: obj.group_ids.map(resolveGroupId) };\n            });\n          }\n          // storage_id → non mappable, conservé\n          return p;\n        };\n\n        const resolveActions = (actions) => (actions||[]).map(action => ({\n          ...action, parameters: resolveParams(action.parameters||{})\n        }));\n\n        const resolveTriggers = (triggers) => (triggers||[]).map(trigger => ({\n          ...trigger, parameters: resolveParams(trigger.parameters||{})\n        }));\n\n        const srcAutoList = await fetch(srcBase + '/API/automations/v1/automations/?per_page=500', { headers: srcH })\n          .then(r=>r.ok?r.json():{}).catch(()=>({}));\n        const dstAutoList = await fetch(dstBase + '/API/automations/v1/automations/?per_page=500', { headers: dstH })\n          .then(r=>r.ok?r.json():{}).catch(()=>({}));\n        const dstAutoByName = {};\n        (dstAutoList.objects||[]).forEach(a=>{ const k=(a.name||'').toLowerCase().trim(); if(k) dstAutoByName[k]=a; });\n\n        let created=0, updated=0, failed=0;\n        for (const src of (srcAutoList.objects||[])) {\n          const key = (src.name||'').toLowerCase().trim();\n          if (!key) continue;\n          const body = {\n            name: src.name,\n            status: 'INACTIVE',\n            triggers: resolveTriggers(src.triggers),\n            conditions: src.conditions||[],\n            actions: resolveActions(src.actions),\n          };\n          const dst = dstAutoByName[key];\n          if (!dst) {\n            const r = await fetch(dstBase + '/API/automations/v1/automations/', {\n              method:'POST', headers:dstH, body:JSON.stringify(body)\n            }).catch(()=>null);\n            if (r?.ok) created++; else failed++;\n          } else if (mode==='add_update'||mode==='overwrite') {\n            const r = await fetch(dstBase + '/API/automations/v1/automations/' + dst.id + '/', {\n              method:'PUT', headers:dstH, body:JSON.stringify(body)\n            }).catch(()=>null);\n            if (r?.ok) updated++; else failed++;\n          }\n        }\n        const parts=[];\n        if (created) parts.push(created+' créées');\n        if (updated) parts.push(updated+' mises à jour');\n        if (failed) parts.push(failed+' échecs');\n        _ddProgTick('automations');\n        results.push('✅ automations'+(parts.length?' : '+parts.join(', '):''));\n      } catch(e) { _ddProgTick('automations'); results.push('❌ automations : '+e.message); }\n      continue;\n    }\n\n    // ✅ System Settings DD : PATCH singleton\n    if (sc === 'systemSettings') {\n      try {\n        // Lire depuis system/current (valeurs système brutes, pas fusionnées avec les teams)\n        const srcSettings = await fetch(srcBase + '/API/settings/v1/system/current/', { headers: srcH })\n          .then(r => r.ok ? r.json() : null).catch(() => null);\n        if (!srcSettings) { results.push('❌ systemSettings : lecture source échouée'); continue; }\n\n        const body = def.body(srcSettings);\n        const r = await fetch(dstBase + '/API/settings/v1/system/current/', {\n          method: 'PATCH', headers: dstH, body: JSON.stringify(body)\n        }).catch(() => null);\n\n        if (r?.ok) results.push('✅ systemSettings : mis à jour');\n        else results.push('❌ systemSettings : PATCH échoué (' + (r?.status || '?') + ')');\n      } catch(e) { results.push('❌ systemSettings : ' + e.message); }\n      continue;\n    }\n\n    // ✅ Saved Searches DD : groupes + searches + nettoyage criteria + résolution metadata_view_id\n    if (sc === 'savedSearches') {\n      try {\n        // Index vues source → destination\n        const srcMdvsR = await fetch(srcBase + '/API/metadata/v1/views/?per_page=500', { headers: srcH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n        const dstMdvsR = await fetch(dstBase + '/API/metadata/v1/views/?per_page=500', { headers: dstH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n        const srcMdvNameById = {};\n        (srcMdvsR.objects || []).forEach(v => { if (v?.id) srcMdvNameById[v.id] = v.name; });\n        const dstMdvIdByName = {};\n        (dstMdvsR.objects || []).forEach(v => { if (v?.name) dstMdvIdByName[v.name.toLowerCase().trim()] = v.id; });\n\n        // Helper : nettoyer + résoudre criteria\n        const cleanCriteria = (raw) => {\n          const SKIP_TERMS = new Set(['created_by_user', 'files.storage_id', 'storage_id']);\n          const cleanTerms = (raw.filter?.terms || []).filter(t => !SKIP_TERMS.has(t.name));\n          const c = { ...raw };\n          if (cleanTerms.length) c.filter = { operator: raw.filter?.operator || 'AND', terms: cleanTerms };\n          else delete c.filter;\n          if (c.metadata_view_id) {\n            const name = srcMdvNameById[c.metadata_view_id];\n            const dstId = name ? dstMdvIdByName[name.toLowerCase().trim()] : null;\n            if (dstId) c.metadata_view_id = dstId; else delete c.metadata_view_id;\n          }\n          return c;\n        };\n\n        // Helper : upsert une saved search sur destination\n        const dstSSByName = {};\n        const upsertSS = async (srcSS, dstGroupId) => {\n          const detail = await fetch(srcBase + '/API/search/v1/search/saved/' + srcSS.id + '/', { headers: srcH })\n            .then(r => r.ok ? r.json() : null).catch(() => null);\n          if (!detail) return null;\n          const raw = detail.search_criteria_document?.criteria || detail.criteria || {};\n          const body = { name: srcSS.name || '', criteria: cleanCriteria(raw) };\n          const key = (srcSS.name || '').toLowerCase().trim();\n\n          let dstSS = dstSSByName[key];\n          if (!dstSS) {\n            const r = await fetch(dstBase + '/API/search/v1/search/saved/', {\n              method: 'POST', headers: dstH, body: JSON.stringify(body)\n            }).catch(() => null);\n            if (r?.ok) { dstSS = await r.json().catch(() => null); if (dstSS) dstSSByName[key] = dstSS; return { dstSS, isNew: true }; }\n            return null;\n          } else if (mode === 'add_update' || mode === 'overwrite') {\n            const r = await fetch(dstBase + '/API/search/v1/search/saved/' + dstSS.id + '/', {\n              method: 'PUT', headers: dstH, body: JSON.stringify(body)\n            }).catch(() => null);\n            if (r?.ok) return { dstSS, isNew: false };\n          }\n          return { dstSS, isNew: false };\n        };\n\n        // Charger destination searches existantes\n        const dstListR = await fetch(dstBase + '/API/search/v1/search/saved/?per_page=500', { headers: dstH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n        (dstListR.objects || []).forEach(s => { const k = (s.name||'').toLowerCase().trim(); if (k) dstSSByName[k] = s; });\n\n        let created = 0, updated = 0, failed = 0;\n\n        // 1) Groupes source → créer groupes destination + assigner searches\n        const srcGroups = await fetch(srcBase + '/API/search/v1/search/saved/groups/?per_page=500', { headers: srcH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n        const dstGroups = await fetch(dstBase + '/API/search/v1/search/saved/groups/?per_page=500', { headers: dstH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n        const dstGroupByName = {};\n        (dstGroups.objects || []).forEach(g => { const k = (g.name||'').toLowerCase().trim(); if (k) dstGroupByName[k] = g; });\n\n        for (const srcGrp of (srcGroups.objects || [])) {\n          const gKey = (srcGrp.name || '').toLowerCase().trim();\n\n          // Créer groupe destination si absent\n          let dstGrp = dstGroupByName[gKey];\n          if (!dstGrp) {\n            const r = await fetch(dstBase + '/API/search/v1/search/saved/group/', {\n              method: 'POST', headers: dstH, body: JSON.stringify({ name: srcGrp.name })\n            }).catch(() => null);\n            if (r?.ok) { dstGrp = await r.json().catch(() => null); if (dstGrp) dstGroupByName[gKey] = dstGrp; }\n          }\n          if (!dstGrp?.id) continue;\n\n          // Searches du groupe source\n          const grpSearches = await fetch(srcBase + '/API/search/v1/search/saved/?group_id=' + srcGrp.id + '&per_page=500', { headers: srcH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n          for (const srcSS of (grpSearches.objects || [])) {\n            const res = await upsertSS(srcSS, dstGrp.id);\n            if (!res) { failed++; continue; }\n            res.isNew ? created++ : updated++;\n            // Assigner à groupe destination\n            await fetch(dstBase + '/API/search/v1/search/saved/group/' + dstGrp.id + '/search/' + res.dstSS.id + '/', {\n              method: 'POST', headers: dstH\n            }).catch(() => null);\n          }\n        }\n\n        // 2) Searches sans groupe (group_id=null)\n        const noGrpList = await fetch(srcBase + '/API/search/v1/search/saved/?group_id=null&per_page=500', { headers: srcH }).then(r => r.ok ? r.json() : {}).catch(() => ({}));\n        for (const srcSS of (noGrpList.objects || [])) {\n          const res = await upsertSS(srcSS, null);\n          if (!res) { failed++; continue; }\n          res.isNew ? created++ : updated++;\n        }\n\n        const parts = [];\n        if (created) parts.push(created + ' créées');\n        if (updated) parts.push(updated + ' mises à jour');\n        if (failed) parts.push(failed + ' échecs');\n        results.push('✅ savedSearches' + (parts.length ? ' : ' + parts.join(', ') : ''));\n      } catch(e) { results.push('❌ savedSearches : ' + e.message); }\n      _ddProgTick('savedSearches');\n      continue;\n    }\n\n    // ✅ Custom Actions : endpoint dynamique par context (/API/assets/v1/custom_actions/{CONTEXT}/)\n    if (sc === 'customActions') {\n      try {\n        const itemsRaw = await fetchAllPages(srcBase, srcH, def.r).catch(()=>[]);\n        const items = def.get ? def.get({ objects: itemsRaw }) : (itemsRaw || []);\n        const dstRaw = await fetchAllPages(dstBase, dstH, def.r).catch(()=>[]);\n        const dstItems = def.get ? def.get({ objects: dstRaw }) : (dstRaw || []);\n        const dstByTitle = {};\n        (dstItems || []).forEach(o => { const k = (o.title||o.name||'').toLowerCase(); if (k) dstByTitle[k] = o; });\n\n        // Construire mdvMap : srcMdvId → dstMdvId (via nom)\n        const srcMdvs = await fetchAllPages(srcBase, srcH, '/API/metadata/v1/views/').catch(()=>[]);\n        const dstMdvs = await fetchAllPages(dstBase, dstH, '/API/metadata/v1/views/').catch(()=>[]);\n        const srcMdvNameById = {};\n        (srcMdvs || []).forEach(v => { if (v?.id) srcMdvNameById[v.id] = v.name; });\n        const dstMdvIdByName = {};\n        (dstMdvs || []).forEach(v => { if (v?.name) dstMdvIdByName[v.name.toLowerCase().trim()] = v.id; });\n        const mdvMap = {}; // srcId -> dstId\n        Object.entries(srcMdvNameById).forEach(([srcId, name]) => {\n          const dstId = dstMdvIdByName[name.toLowerCase().trim()];\n          if (dstId) mdvMap[srcId] = dstId;\n        });\n\n        let created = 0, updated = 0, failed = 0;\n        for (const src of (items || [])) {\n          const context = String(src.context || 'BULK').toUpperCase();\n          const epContext = '/API/assets/v1/custom_actions/' + context + '/';\n          const key = (src.title||src.name||'').toLowerCase();\n          const dst = dstByTitle[key];\n          const body = def.body(src, !dst, mdvMap);\n\n          if (!dst) {\n            const r = await fetch(dstBase + epContext, {\n              method: 'POST', headers: dstH, body: JSON.stringify(body)\n            }).catch(() => null);\n            if (r?.ok) created++; else failed++;\n          } else if (mode === 'add_update' || mode === 'overwrite') {\n            const r = await fetch(dstBase + epContext + dst.id + '/', {\n              method: 'PUT', headers: dstH, body: JSON.stringify(body)\n            }).catch(() => null);\n            if (r?.ok) updated++; else failed++;\n          }\n        }\n        const parts = [];\n        if (created) parts.push(created + ' créées');\n        if (updated) parts.push(updated + ' mises à jour');\n        if (failed) parts.push(failed + ' échecs');\n        results.push('✅ customActions' + (parts.length ? ' : ' + parts.join(', ') : ''));\n      } catch(e) { results.push('❌ customActions : ' + e.message); }\n      continue;\n    }\n\n    try {\n      const itemsRaw = await fetchAllPages(srcBase, srcH, def.r).catch(()=>[]);\n      let items = def.get ? def.get({ objects: itemsRaw }) : (itemsRaw || []);\n      // ✅ Filtre teams système (Everyone / Administrator) en Domaine↔Domaine\n      if (sc === 'teams' && !cfg.includeSysTeams) {\n        items = (items || []).filter(t => !isSystemTeam(t?.name || t?.nom || ''));\n      }\n      // ✅ Filtre MDV système (Segment Tags) en Domaine↔Domaine\n      if (sc === 'metadataViews' && typeof wfdIncludeSystemMetadataViews === 'function' && typeof wfdIsSystemMetadataView === 'function') {\n      if (!wfdIncludeSystemMetadataViews()) {\n      items = (items || []).filter(v => !wfdIsSystemMetadataView(v?.name || v?.nom || v?.title || v));\n  }\n}\n      const dstRaw = await fetchAllPages(dstBase, dstH, def.r).catch(()=>[]);\n      const dstItems = def.get ? def.get({ objects: dstRaw }) : (dstRaw || []);\n      const keyFn = o => (o.name||o.title||'').toLowerCase();\n      const { created, updated, deleted, failed, failures } = await applySyncMode(\n        mode, items, dstItems, dstBase, dstH, def.w, def.body, keyFn\n      );\n      const parts = [];\n      if (created) parts.push(created + ' créés');\n      if (updated) parts.push(updated + ' mis à jour');\n      if (deleted) parts.push(deleted + ' supprimés');\n      if (failed) {\n        const top = Object.entries(failures || {}).sort((a,b)=>b[1]-a[1]).slice(0,3)\n          .map(([k,v])=>k+':'+v).join(', ');\n        parts.push(failed + ' échecs' + (top ? ' ('+top+')' : ''));\n      }\n      results.push('✅ ' + sc + (parts.length ? ' : ' + parts.join(', ') : ''));\n    } catch(e) { results.push('❌ '+sc+' : '+e.message); }\n  }\n  \n  // =======================================================\n// DD — Metadata Views : création avec view_fields (requis)\n// =======================================================\nasync function syncMetadataViewsDD() {\n  const stats = { created: 0, updated: 0, failed: 0, failures: {} };\n\n  // 1) Charger views source + destination\n  const srcViews = await fetchAllPages(srcBase, srcH, '/API/metadata/v1/views/?per_page=500').catch(()=>[]);\n  const dstViews = await fetchAllPages(dstBase, dstH, '/API/metadata/v1/views/?per_page=500').catch(()=>[]);\n\n  // 2) Charger fields source/destination pour mapper les field_id\n  const srcFields = await fetchAllPages(srcBase, srcH, '/API/metadata/v1/fields/?per_page=500').catch(()=>[]);\n  const dstFields = await fetchAllPages(dstBase, dstH, '/API/metadata/v1/fields/?per_page=500').catch(()=>[]);\n\n  const srcFieldNameById = {};\n  (srcFields || []).forEach(f => { if (f?.id && f?.name) srcFieldNameById[f.id] = f.name; });\n\n  const dstFieldIdByName = {};\n  (dstFields || []).forEach(f => {\n    const name = String(f?.name || '').trim();\n    if (!name) return;\n    // Sur certains tenants, l’identifiant utilisable peut être id ou name\n    dstFieldIdByName[name] = f.id || f.name;\n  });\n\n  // 3) Index destination views by name\n  const dstViewIdByName = {};\n  (dstViews || []).forEach(v => {\n    const k = String(v?.name || '').toLowerCase().trim();\n    if (k) dstViewIdByName[k] = v.id;\n  });\n\n  // helper: récupérer view_fields d’une vue source\n  async function fetchViewFieldsSrc(viewId) {\n    // Essai 1 : GET view detail (souvent contient view_fields)\n    const d = await fetch(srcBase + '/API/metadata/v1/views/' + viewId + '/', { headers: srcH })\n      .then(r => r.ok ? r.json() : null)\n      .catch(()=>null);\n\n    if (d && Array.isArray(d.view_fields) && d.view_fields.length) return d.view_fields;\n\n    // Essai 2 : fallback endpoint fields\n    const f = await fetch(srcBase + '/API/metadata/v1/views/' + viewId + '/fields/?per_page=500', { headers: srcH })\n      .then(r => r.ok ? r.json() : null)\n      .catch(()=>null);\n\n    return (f && Array.isArray(f.objects)) ? f.objects : [];\n  }\n\n  // helper: mapper un view_field source -> payload destination\n  function mapViewField(vf, idx) {\n    // Cas séparateur : payload spécial, pas de field_id\n    if (vf.field_type === '__separator__' || vf.name === '__separator__') {\n      return {\n        name: '__separator__',\n        label: vf.label || '',\n        field_type: '__separator__'\n      };\n    }\n\n    // vf peut contenir field_id OU name selon endpoint\n    const srcFieldId = vf.field_id || vf.id || null;\n    const srcFieldName = vf.name || vf.field_name || (srcFieldId ? srcFieldNameById[srcFieldId] : null);\n\n    if (!srcFieldName) return null;\n    const dstFieldId = dstFieldIdByName[srcFieldName];\n    if (!dstFieldId) return null;\n\n    // payload minimal: field_id + name (requis par Iconik) + ordre\n    const out = { field_id: dstFieldId, name: srcFieldName, sort_order: idx };\n\n    // best-effort : conserver overrides si présents (sans forcer)\n    const allow = ['required','read_only','hide_if_not_set','use_in_filters','string_exact','display_as_warning','block_assets'];\n    allow.forEach(k => { if (vf[k] != null) out[k] = vf[k]; });\n\n    // mapped_field_name (inherited from) si présent\n    if (vf.mapped_field_name) out.mapped_field_name = vf.mapped_field_name;\n\n    return out;\n  }\n\n  // 4) CREATE/UPDATE views\n  for (const v of (srcViews || [])) {\n    const name = String(v?.name || '').trim();\n    if (!name) continue;\n\n    const fieldsSrc = await fetchViewFieldsSrc(v.id).catch(()=>[]);\n    const view_fields = (fieldsSrc || [])\n      .map((vf, idx) => mapViewField(vf, idx))\n      .filter(Boolean);\n\n    // ⚠️ view_fields vide → vue système (ex: Segment Tags) → ignorer silencieusement\n    if (!view_fields.length) {\n      stats.skipped = (stats.skipped || 0) + 1;\n      continue;\n    }\n\n    const body = { name, description: (v.description || ''), view_fields };\n\n    const k = name.toLowerCase();\n    const dstId = dstViewIdByName[k];\n\n    try {\n      if (!dstId) {\n        const r = await fetch(dstBase + '/API/metadata/v1/views/', {\n          method:'POST', headers: dstH, body: JSON.stringify(body)\n        }).catch(()=>null);\n        if (r?.ok) stats.created++;\n        else {\n          stats.failed++;\n          const s = r?.status || 'ERR'; stats.failures[s] = (stats.failures[s]||0)+1;\n        }\n      } else if (mode === 'add_update' || mode === 'overwrite') {\n        const r = await fetch(dstBase + '/API/metadata/v1/views/' + dstId + '/', {\n          method:'PUT', headers: dstH, body: JSON.stringify(body)\n        }).catch(()=>null);\n        if (r?.ok) stats.updated++;\n        else {\n          stats.failed++;\n          const s = r?.status || 'ERR'; stats.failures[s] = (stats.failures[s]||0)+1;\n        }\n      }\n    } catch (e) {\n      stats.failed++;\n      stats.failures.EXCEPTION = (stats.failures.EXCEPTION || 0) + 1;\n    }\n  }\n\n  // ── Synchroniser les associations vue ↔ object_type (catégorie default) ──\n  // Reconstruire dstViewIdByName après création des vues (pour inclure les nouvelles)\n  const dstViewsFresh = await fetchAllPages(dstBase, dstH, '/API/metadata/v1/views/?per_page=500').catch(()=>[]);\n  (dstViewsFresh || []).forEach(v => {\n    const n = String(v?.name || '').toLowerCase().trim();\n    if (n && v?.id) dstViewIdByName[n] = v.id;\n  });\n\n  // Pour chaque object_type, lire view_ids source, résoudre vers IDs destination, PUT\n  // Nom de catégorie par object_type (segments utilise 'generic' au lieu de 'default')\n  const OBJ_TYPES = [\n    { type: 'assets',         cat: 'default' },\n    { type: 'collections',    cat: 'default' },\n    { type: 'segments',       cat: 'generic' },\n    { type: 'custom_actions', cat: 'default' },\n    { type: 'search',         cat: 'default' },\n  ];\n  for (const { type: objType, cat: catName } of OBJ_TYPES) {\n    try {\n      const srcCat = await fetch(srcBase + '/API/metadata/v1/' + objType + '/categories/' + catName + '/views/', { headers: srcH })\n        .then(r => r.ok ? r.json() : null).catch(() => null);\n      if (!srcCat) continue;\n\n      // Résoudre view_ids source → noms → IDs destination\n      // srcViews = liste des vues source (chargée en début de syncMetadataViewsDD)\n      const srcViewNameById = {};\n      (srcViews || []).forEach(v => { if (v?.id) srcViewNameById[v.id] = v.name; });\n\n      const srcViewIds = srcCat.view_ids || (srcCat.objects || []).map(v => v.id);\n      const dstViewIds = (srcViewIds || [])\n        .map(srcId => {\n          const name = srcViewNameById[srcId];\n          if (!name) return null;\n          return dstViewIdByName[name.toLowerCase().trim()];\n        })\n        .filter(Boolean);\n\n      if (!dstViewIds.length) continue;\n\n      // Lire catégorie destination pour merger (add_only) ou écraser (overwrite)\n      const dstCat = await fetch(dstBase + '/API/metadata/v1/' + objType + '/categories/' + catName + '/', { headers: dstH })\n        .then(r => r.ok ? r.json() : null).catch(() => null);\n\n      let finalIds = dstViewIds;\n      if (mode === 'add_only' && dstCat?.view_ids) {\n        const existing = new Set(dstCat.view_ids);\n        dstViewIds.forEach(id => existing.add(id));\n        finalIds = [...existing];\n      }\n\n      // Utiliser le nom exact de la catégorie dst (peut être \"Default\" avec majuscule)\n      const dstCatName = dstCat?.name || (catName === 'generic' ? 'Generic' : 'Default');\n      await fetch(dstBase + '/API/metadata/v1/' + objType + '/categories/' + encodeURIComponent(dstCatName) + '/', {\n        method: 'PUT',\n        headers: dstH,\n        body: JSON.stringify({ name: dstCatName, label: dstCatName, view_ids: finalIds })\n      }).catch(() => null);\n\n    } catch (e) { /* silencieux */ }\n  }\n  stats.object_types_synced = OBJ_TYPES.length; // assets/collections/segments/custom_actions/search\n\n  return stats;\n}\n\n  \n  // ─────────────────────────────────────────────────────────────\n// ✅ Phase 1bis : CATEGORIES inter-domaines (Domaine ↔ Domaine)\n// Source et destination = endpoints par object_type, comme Domaine→Site.\n// Support modes : add_only / add_update / overwrite\n// Garde-fou : ne supprime jamais default/generic/tag\n// ─────────────────────────────────────────────────────────────\nif (active.includes('categories')) {\n\n  // Endpoints catégories par object_type (même structure que ton Domaine→Site) \n  const catEndpoints = {\n    assets: '/API/metadata/v1/assets/categories/',\n    collections: '/API/metadata/v1/collections/categories/',\n    segments: '/API/metadata/v1/segments/categories/',\n    custom_actions: '/API/metadata/v1/custom_actions/categories/'\n  };\n\n  // Helpers : lire toutes les catégories d’un domaine (agrégation par name)\n  const fetchViewsMaps = async (baseUrl, H) => {\n    const r = await fetch(baseUrl + '/API/metadata/v1/views/?per_page=500', { headers: H })\n      .then(x => x.ok ? x.json() : ({ objects: [] }))\n      .catch(() => ({ objects: [] }));\n    const idToName = {};\n    const nameToId = {};\n    (r.objects || []).forEach(v => {\n      const name = String(v.name || '').trim();\n      const key = name.toLowerCase();\n      if (v.id && name) {\n        idToName[v.id] = name;\n        nameToId[key] = v.id;\n      }\n    });\n    return { idToName, nameToId };\n  };\n\n  const srcViews = await fetchViewsMaps(srcBase, srcH);\n  const dstViews = await fetchViewsMaps(dstBase, dstH);\n\n  // Lire catégories source et les agréger : nameKey -> {name,label,object_types[], metadataViews[]}\n  const srcByName = new Map(); // nameKey -> agg\n  for (const [type, ep] of Object.entries(catEndpoints)) {\n    const r = await fetch(srcBase + ep + '?per_page=500', { headers: srcH })\n      .then(x => x.ok ? x.json() : ({ objects: [] }))\n      .catch(() => ({ objects: [] }));\n\n    (r.objects || []).forEach(cat => {\n      const name = String(cat.name || '').trim();\n      if (!name) return;\n      const key = name.toLowerCase();\n\n      const cur = srcByName.get(key) || {\n        name,\n        label: String(cat.label || cat.name || '').trim(),\n        object_types: [],\n        metadataViews: [] // NOMS de vues (pas ids)\n      };\n\n      if (!cur.object_types.includes(type)) cur.object_types.push(type);\n\n      // Convertir view_ids -> view names via srcViews.idToName\n      (cat.view_ids || []).forEach(vid => {\n        const vn = srcViews.idToName[vid];\n        if (vn && !cur.metadataViews.includes(vn)) cur.metadataViews.push(vn);\n      });\n\n      // conserver label le plus \"riche\"\n      if (cat.label && String(cat.label).length > (cur.label || '').length) cur.label = String(cat.label).trim();\n\n      srcByName.set(key, cur);\n    });\n  }\n\n  // Lire catégories destination par type : type -> (nameKey -> obj)\n  const dstByType = {};\n  for (const [type, ep] of Object.entries(catEndpoints)) {\n    const r = await fetch(dstBase + ep + '?per_page=500', { headers: dstH })\n      .then(x => x.ok ? x.json() : ({ objects: [] }))\n      .catch(() => ({ objects: [] }));\n\n    const map = {};\n    (r.objects || []).forEach(cat => {\n      const key = String(cat.name || '').toLowerCase().trim();\n      if (key) map[key] = cat;\n    });\n    dstByType[type] = map;\n  }\n\n  // Filtre système src/dst indépendants\n  const _sysCatsEl_src = null\n    || null\n    || null;\n  const _sysCatsEl_dst = null\n    || null\n    || null;\n  const includeSysCats     = _sysCatsEl_src ? _sysCatsEl_src.checked : (wfdIncludeSystemCategories());\n  // Dst = src (toggles fusionnés) — hidden input synchronisé ou fallback src\n  const includeSysCatsDst  = _sysCatsEl_dst ? (_sysCatsEl_dst.checked ?? (_sysCatsEl_dst.value === '1')) : includeSysCats;\n  const SYSTEM_CAT_KEYS = new Set(['default', 'generic', 'tag']); // garde-fou suppression\n\n  // desiredByType[type] = Set(nameKey) pour overwrite\n  const desiredByType = {};\n\n  // CREATE / UPDATE\n  let created = 0, updated = 0, deleted = 0, skipped = 0;\n\n  for (const agg of srcByName.values()) {\n    const nameKey = String(agg.name || '').toLowerCase().trim();\n    if (!nameKey) { skipped++; continue; }\n\n    // Exclusion par défaut des catégories système (source)\n    if (!includeSysCats && SYSTEM_CAT_KEYS.has(nameKey)) { skipped++; continue; }\n\n    // Construire view_ids destination à partir des view names source\n    const view_ids = (agg.metadataViews || [])\n      .map(vn => dstViews.nameToId[String(vn || '').toLowerCase().trim()])\n      .filter(Boolean);\n\n    const body = { name: agg.name, label: agg.label || agg.name, view_ids };\n\n    for (const type of (agg.object_types || [])) {\n      const ep = catEndpoints[type];\n      if (!ep) continue;\n\n      if (!desiredByType[type]) desiredByType[type] = new Set();\n      desiredByType[type].add(nameKey);\n\n      const existing = dstByType[type]?.[nameKey];\n\n      // add_only : si existe, skip\n      if (mode === 'add_only' && existing) { skipped++; continue; }\n\n      if (!existing) {\n        const r = await fetch(dstBase + ep, {\n          method: 'POST',\n          headers: dstH,\n          body: JSON.stringify(body)\n        }).catch(() => null);\n        if (r && r.ok) created++;\n      } else {\n        if (mode === 'add_update' || mode === 'overwrite') {\n          const r = await fetch(dstBase + ep + existing.id + '/', {\n            method: 'PUT',\n            headers: dstH,\n            body: JSON.stringify(body)\n          }).catch(() => null);\n          if (r && r.ok) updated++;\n        }\n      }\n    }\n  }\n\n  // DELETE extras (overwrite) — par type, avec garde-fou system cats\n  if (mode === 'overwrite') {\n    for (const [type, map] of Object.entries(dstByType)) {\n      const ep = catEndpoints[type];\n      if (!ep) continue;\n\n      const desired = desiredByType[type] || new Set();\n\n      for (const [nameKey, existing] of Object.entries(map || {})) {\n        if (!existing?.id) continue;\n\n        // Garde-fou absolu : ne jamais supprimer default/generic/tag\n        if (SYSTEM_CAT_KEYS.has(nameKey)) continue;\n\n        // Si catégories système dst exclues, ne pas les supprimer non plus\n        if (!includeSysCatsDst && SYSTEM_CAT_KEYS.has(nameKey)) continue;\n\n        // Si catégorie non désirée -> DELETE\n        if (!desired.has(nameKey)) {\n          await fetch(dstBase + ep + existing.id + '/', {\n            method: 'DELETE',\n            headers: dstH\n          }).catch(() => null);\n          deleted++;\n        }\n      }\n    }\n  }\n\n  results.push(`✅ categories inter-domaines : ${created} créées, ${updated} mises à jour, ${deleted} supprimées, ${skipped} ignorées`);\n}\n\n\n  // ── Export Locations ──────────────────────────────────────────────────────\n  // Sync : crée/met à jour les export locations (sans la partie storage,\n  // infrastructure-dépendante). ACLs teams + users copiées depuis la source.\n  if (active.includes('exportLocations')) {\n    try {\n      const srcELs = await fetchAllPages(srcBase, srcH, '/API/files/v1/export_locations/?per_page=500').catch(() => []);\n      const dstELs = await fetchAllPages(dstBase, dstH, '/API/files/v1/export_locations/?per_page=500').catch(() => []);\n\n      const dstELByName = {};\n      (dstELs || []).forEach(e => { const k = (e.name || '').toLowerCase().trim(); if (k) dstELByName[k] = e; });\n\n      // Index teams src→dst par nom (pour résolution ACLs)\n      const srcTeamsEL = await fetchAllPages(srcBase, srcH, '/API/users/v1/teams/?per_page=500').catch(() => []);\n      const dstTeamsEL = await fetchAllPages(dstBase, dstH, '/API/users/v1/teams/?per_page=500').catch(() => []);\n      const srcTeamNameById = {};\n      srcTeamsEL.forEach(t => { if (t?.id) srcTeamNameById[t.id] = t.name || ''; });\n      const dstTeamIdByName = {};\n      dstTeamsEL.forEach(t => { if (t?.name) dstTeamIdByName[t.name.toLowerCase().trim()] = t.id; });\n\n      // Index users src→dst par email\n      const srcUsersEL = await fetchAllPages(srcBase, srcH, '/API/users/v1/users/?per_page=500').catch(() => []);\n      const dstUsersEL = await fetchAllPages(dstBase, dstH, '/API/users/v1/users/?per_page=500').catch(() => []);\n      const srcUserEmailById = {};\n      srcUsersEL.forEach(u => { if (u?.id) srcUserEmailById[u.id] = u.email || ''; });\n      const dstUserIdByEmail = {};\n      dstUsersEL.forEach(u => { if (u?.email) dstUserIdByEmail[u.email.toLowerCase().trim()] = u.id; });\n\n      let created = 0, updated = 0, failed = 0;\n\n      for (const srcEL of (srcELs || [])) {\n        const nameKey = (srcEL.name || '').toLowerCase().trim();\n        if (!nameKey) continue;\n\n        // Corps sans storage_id (infrastructure-dépendant)\n        const body = {\n          name:                         srcEL.name,\n          description:                  srcEL.description || '',\n          path:                         srcEL.path || '',\n          export_original:              !!srcEL.export_original,\n          export_proxy:                 !!srcEL.export_proxy,\n          export_posters:               !!srcEL.export_posters,\n          export_metadata:              !!srcEL.export_metadata,\n          export_transcriptions:        !!srcEL.export_transcriptions,\n          include_original_extension:   !!srcEL.include_original_extension,\n        };\n        if (srcEL.metadata_view)          body.metadata_view          = srcEL.metadata_view;\n        if (srcEL.metadata_format)        body.metadata_format        = srcEL.metadata_format;\n        if (srcEL.transcription_format)   body.transcription_format   = srcEL.transcription_format;\n        if (srcEL.export_to_asset_folder) body.export_to_asset_folder = srcEL.export_to_asset_folder;\n        if (Array.isArray(srcEL.transcode_profile_ids) && srcEL.transcode_profile_ids.length)\n          body.transcode_profile_ids = srcEL.transcode_profile_ids;\n\n        const dstEL = dstELByName[nameKey];\n        let dstELId = dstEL?.id || null;\n\n        if (!dstEL) {\n          // Créer\n          const r = await fetch(dstBase + '/API/files/v1/export_locations/', {\n            method: 'POST', headers: dstH, body: JSON.stringify(body)\n          }).catch(() => null);\n          if (r?.ok) {\n            const obj = await r.json().catch(() => null);\n            dstELId = obj?.id || null;\n            created++;\n          } else { failed++; continue; }\n        } else if (mode === 'add_update' || mode === 'overwrite') {\n          // Mettre à jour\n          const r = await fetch(dstBase + '/API/files/v1/export_locations/' + dstEL.id + '/', {\n            method: 'PUT', headers: dstH, body: JSON.stringify(body)\n          }).catch(() => null);\n          if (r?.ok) updated++;\n          else { failed++; }\n        }\n\n        if (!dstELId) continue;\n\n        // ACLs : groupes\n        const srcAcl = await fetch(srcBase + '/API/acls/v1/acl/export_locations/' + srcEL.id + '/', { headers: srcH })\n          .then(r => r.ok ? r.json() : null).catch(() => null);\n        if (!srcAcl) continue;\n\n        for (const ga of (srcAcl.groups_acl || [])) {\n          const teamName = srcTeamNameById[ga.group_id];\n          if (!teamName) continue;\n          if (!cfg.includeSysTeams && isSystemTeam(teamName)) continue;\n          const dstGId = dstTeamIdByName[teamName.toLowerCase().trim()];\n          if (!dstGId) continue;\n          await fetch(dstBase + '/API/acls/v1/groups/' + dstGId + '/acl/export_locations/' + dstELId + '/', {\n            method: 'PUT', headers: dstH,\n            body: JSON.stringify({ permissions: ga.permissions || ['read'] })\n          }).catch(() => null);\n        }\n\n        // ACLs : users\n        for (const ua of (srcAcl.users_acl || [])) {\n          const email = srcUserEmailById[ua.user_id];\n          if (!email) continue;\n          const dstUId = dstUserIdByEmail[email.toLowerCase().trim()];\n          if (!dstUId) continue;\n          await fetch(dstBase + '/API/acls/v1/users/' + dstUId + '/acl/export_locations/' + dstELId + '/', {\n            method: 'PUT', headers: dstH,\n            body: JSON.stringify({ permissions: ua.permissions || ['read'] })\n          }).catch(() => null);\n        }\n      }\n\n      const parts = [];\n      if (created) parts.push(created + ' créées');\n      if (updated) parts.push(updated + ' mises à jour');\n      if (failed)  parts.push(failed  + ' échecs');\n      results.push('✅ exportLocations' + (parts.length ? ' : ' + parts.join(', ') : ''));\n    } catch(e) { results.push('❌ exportLocations : ' + e.message); }\n  }\n\n  // ── Phase 2 : Associations inter-domaines ────────────────────────────────────\n  const doAssocDD = active.includes('teams') || active.includes('roleGroups');\n  if (doAssocDD) {\n\n    // Lire entités source avec rôles inclus (GroupWithRolesElasticSchema)\n    const srcTeamsR = await fetch(srcBase+'/API/users/v1/teams/?per_page=500',{headers:srcH}).then(r=>r.json()).catch(()=>({}));\n    const srcRGsR   = await fetch(srcBase+'/API/users/v1/role_groups/?per_page=500',{headers:srcH}).then(r=>r.json()).catch(()=>({}));\n    // Charger TOUTES les collections src via recherche (pas seulement racines)\n    const _srcColsAll = await (async () => {\n      let all = [], page = 1;\n      while (true) {\n        const r = await fetch(srcBase+'/API/search/v1/search/?per_page=500&page='+page, {\n          method:'POST', headers:{...srcH,'Content-Type':'application/json'},\n          body:JSON.stringify({doc_types:['collections']})\n        }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        all = all.concat(r.objects||[]);\n        if (!r.objects?.length || page>=(r.pages||1) || page>50) break;\n        page++;\n      }\n      return all;\n    })();\n    const srcColsR = {objects: _srcColsAll};\n    const srcViewsR = await fetch(srcBase+'/API/metadata/v1/views/?per_page=500',{headers:srcH}).then(r=>r.json()).catch(()=>({}));\n\n    // Index source : id→nom (pour résolution lors de lecture ACLs)\n    const srcColByid  = {}; (srcColsR.objects||[]).forEach(c=>{ srcColByid[c.id]  = c.name; });\n    const srcViewById = {}; (srcViewsR.objects||[]).forEach(v=>{ srcViewById[v.id] = v.name; });\n\n    // Index destination : nom→id\n    const dstTeamsR = await fetch(dstBase+'/API/users/v1/teams/?per_page=500',{headers:dstH}).then(r=>r.json()).catch(()=>({}));\n    // Charger TOUTES les collections dst via recherche\n    const _dstColsAll = await (async () => {\n      let all = [], page = 1;\n      while (true) {\n        const r = await fetch(dstBase+'/API/search/v1/search/?per_page=500&page='+page, {\n          method:'POST', headers:{...dstH,'Content-Type':'application/json'},\n          body:JSON.stringify({doc_types:['collections']})\n        }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        all = all.concat(r.objects||[]);\n        if (!r.objects?.length || page>=(r.pages||1) || page>50) break;\n        page++;\n      }\n      return all;\n    })();\n    const dstColsR = {objects: _dstColsAll};\n    const dstViewsR = await fetch(dstBase+'/API/metadata/v1/views/?per_page=500',{headers:dstH}).then(r=>r.json()).catch(()=>({}));\n    const dstRGsR   = await fetch(dstBase+'/API/users/v1/role_groups/?per_page=500',{headers:dstH}).then(r=>r.json()).catch(()=>({}));\n\n    const dstTeamMap = {};\n\n  // ─────────────────────────────────────────────────────────────\n  // Teams settings — /API/settings/v1/team/{groupId}/\n  // ─────────────────────────────────────────────────────────────\n  const TEAM_SETTINGS_SKIP = new Set(['group_id','system_domain_id','client_ip','logo_storage_id','logo_url','jobs_dashboard','allowed_ips']);\n  const TEAM_VIEW_KEYS = ['filters_default_metadata_view_id','search_results_asset_metadata_view_id','search_results_collection_metadata_view_id','search_view_id'];\n\n  async function copyTeamSettingsDD() {\n    if (!active.includes('teams')) return;\n\n    const srcViewNameById = {};\n    (srcViewsR.objects || []).forEach(v => { if (v?.id) srcViewNameById[v.id] = v.name; });\n    const dstViewIdByName = {};\n    (dstViewsR.objects || []).forEach(v => { if (v?.name) dstViewIdByName[v.name.toLowerCase().trim()] = v.id; });\n\n    const resolveColId = (srcId) => {\n      if (!srcId) return null;\n      if (typeof ddColIdMap !== 'undefined' && ddColIdMap && ddColIdMap[srcId]) return ddColIdMap[srcId];\n      return null;\n    };\n\n    // Maps storages src→dst par nom (pour default_upload_storage_id)\n    const srcStorageNameById = {};\n    const dstStorageIdByName = {};\n    try {\n      const [srcSt, dstSt] = await Promise.all([\n        fetch(srcBase + '/API/files/v1/storages/?per_page=500', { headers: srcH }).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]})),\n        fetch(dstBase + '/API/files/v1/storages/?per_page=500', { headers: dstH }).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]})),\n      ]);\n      (srcSt.objects||[]).forEach(s => { if (s?.id && s?.name) srcStorageNameById[s.id] = s.name; });\n      (dstSt.objects||[]).forEach(s => { if (s?.name) dstStorageIdByName[s.name.toLowerCase().trim()] = s.id; });\n    } catch(_) {}\n\n    let copied = 0, skipped = 0, failed = 0;\n\n    for (const srcTeam of (srcTeamsR.objects || [])) {\n      const teamKey = String(srcTeam?.name || '').toLowerCase().trim();\n      if (!teamKey) { skipped++; continue; }\n      if (!cfg.includeSysTeams && isSystemTeam(teamKey)) { skipped++; continue; }\n\n      const dstTeamId = dstTeamMap[teamKey];\n      if (!dstTeamId) { skipped++; continue; }\n\n      // Fetch détail team source pour description/saml fields\n      const srcTeamDetail = await fetch(srcBase + '/API/users/v1/teams/' + srcTeam.id + '/', { headers: srcH })\n        .then(r => r.ok ? r.json() : null).catch(() => null);\n\n      // PATCH team destination avec description + SAML fields\n      if (srcTeamDetail) {\n        const teamBody = {};\n        if (srcTeamDetail.description) teamBody.description = srcTeamDetail.description;\n        if (srcTeamDetail.default_user_type) teamBody.default_user_type = srcTeamDetail.default_user_type;\n        if (srcTeamDetail.saml_primary_group_priority != null) teamBody.saml_primary_group_priority = srcTeamDetail.saml_primary_group_priority;\n        if (Object.keys(teamBody).length) {\n          teamBody.name = srcTeam.name; // requis par Iconik\n          await fetch(dstBase + '/API/users/v1/teams/' + dstTeamId + '/', {\n            method: 'PUT', headers: dstH, body: JSON.stringify(teamBody)\n          }).catch(() => null);\n        }\n      }\n\n      const srcSettings = await fetch(srcBase + '/API/settings/v1/team/' + srcTeam.id + '/', { headers: srcH })\n        .then(r => r.ok ? r.json() : null).catch(() => null);\n      if (!srcSettings) { skipped++; continue; }\n\n      const body = {};\n      // Clés qui acceptent null explicitement (réinitialise l'héritage domaine)\n      const NULLABLE_KEYS = new Set(['search_in_transcriptions','append_asset_uuid_to_downloads',\n        'use_asset_name_on_download','hide_favourites','collections_get_parent_acls',\n        'acl_template_id','share_expiration_time','date_format','datetime_format']);\n      for (const [k, v] of Object.entries(srcSettings)) {\n        if (TEAM_SETTINGS_SKIP.has(k) || v === undefined) continue;\n        // Envoyer null explicitement pour les clés nullable (reset vers héritage domaine)\n        if (v === null) {\n          if (NULLABLE_KEYS.has(k)) body[k] = null;\n          continue;\n        }\n        if (TEAM_VIEW_KEYS.includes(k)) {\n          const viewName = srcViewNameById[v];\n          const dstId = viewName ? dstViewIdByName[viewName.toLowerCase().trim()] : null;\n          if (dstId) body[k] = dstId;\n          continue;\n        }\n        if (k === 'required_metadata_views' && Array.isArray(v)) {\n          const resolvedIds = v.map(srcId => {\n            const viewName = srcViewNameById[srcId];\n            return viewName ? dstViewIdByName[viewName.toLowerCase().trim()] : null;\n          }).filter(Boolean);\n          if (resolvedIds.length) body[k] = resolvedIds;\n          continue;\n        }\n        if (k === 'home_page' && typeof v === 'string' && v.startsWith('/collection/')) {\n          const dstColId = resolveColId(v.replace('/collection/', ''));\n          if (dstColId) body[k] = '/collection/' + dstColId;\n          continue;\n        }\n        if (k === 'default_upload_storage_id') {\n          const storageName = srcStorageNameById[v];\n          const dstStorageId = storageName ? dstStorageIdByName[storageName.toLowerCase().trim()] : null;\n          if (dstStorageId) body[k] = dstStorageId;\n          // Si pas d'équivalent en dst, on skip (storage propre au domaine)\n          continue;\n        }\n        body[k] = v;\n      }\n\n      if (!Object.keys(body).length) { skipped++; continue; }\n\n      const r = await fetch(dstBase + '/API/settings/v1/team/' + dstTeamId + '/', {\n        method: 'PATCH', headers: dstH, body: JSON.stringify(body)\n      }).catch(() => null);\n      if (r?.ok) copied++; else failed++;\n    }\n\n    __wfd_dd_team_settings_stats = { copied, skipped, failed, at: new Date().toISOString() };\n    if (Array.isArray(results)) {\n      const parts = [];\n      if (copied) parts.push(copied + ' copiés');\n      if (skipped) parts.push(skipped + ' ignorés');\n      if (failed) parts.push(failed + ' échecs');\n      results.push('✅ Teams settings' + (parts.length ? ' : ' + parts.join(', ') : ''));\n    }\n  }\n\n       (dstTeamsR.objects || []).forEach(t => {\n       const key = (t.name || '').toLowerCase().trim();\n       if (!key) return;\n       if (!cfg.includeSysTeams && isSystemTeam(key)) return; // default OFF\n       dstTeamMap[key] = t.id;\n    });\n    // ── Recharger les collections destination APRÈS la sync (les nouvelles collections\n    //    créées en phase 1 ne seraient pas dans dstColsR chargé avant la sync) ──\n    const _dstColsFresh = await (async () => {\n      let all = [], page = 1;\n      while (true) {\n        const r = await fetch(dstBase+'/API/search/v1/search/?per_page=500&page='+page, {\n          method:'POST', headers:{...dstH,'Content-Type':'application/json'},\n          body:JSON.stringify({doc_types:['collections']})\n        }).then(r=>r.ok?r.json():{}).catch(()=>({}));\n        all = all.concat(r.objects||[]);\n        if (!r.objects?.length || page>=(r.pages||1) || page>50) break;\n        page++;\n      }\n      return all;\n    })();\n    log('── ACLs collections : ' + _dstColsFresh.length + ' collections destination chargées');\n\n    // Index par titre seul (fallback) — on détecte les doublons pour ne pas résoudre à tort\n    const dstColMap = {};\n    const dstColMapDupes = new Set();\n    _dstColsFresh.forEach(c => {\n      const k = (c.title||c.name||'').toLowerCase().trim();\n      if (!k) return;\n      if (dstColMap[k]) dstColMapDupes.add(k);\n      else dstColMap[k] = c.id;\n    });\n    if (dstColMapDupes.size > 0) {\n      log('  ⚠️ ACLs : ' + dstColMapDupes.size + ' titre(s) en doublon — résolution par ddColIdMap uniquement pour ces collections');\n    }\n    const dstViewMap = {}; (dstViewsR.objects || []).forEach(v => {\n    const nameKey = String(v.name || '').toLowerCase().trim();\n    if (!nameKey) return;\n    // ✅ Filtre MDV système (Segment Tags) si toggle OFF\n    if (typeof wfdIncludeSystemMetadataViews === 'function' && typeof wfdIsSystemMetadataView === 'function') {\n    if (!wfdIncludeSystemMetadataViews() && wfdIsSystemMetadataView(v.name)) return;\n  }\n\n    dstViewMap[nameKey] = v.id;\n});\n\n    const dstRGMap   = {}; (dstRGsR.objects||[]).forEach(rg=>{ dstRGMap[(rg.name||'').toLowerCase()]  = rg.id; });\n\n    // Teams → ACLs (Collections + MD Views + Saved Searches + Storages)\n    // On lit les ACLs par objet sur la source (GET /API/acls/v1/acl/{type}/{key}/)\n    // puis on les recrée sur la destination avec PUT /API/acls/v1/groups/{gid}/acl/{type}/{key}/\nif (active.includes('teams')) {\n\n  // --- index source teams : id -> name (pour résoudre group_id -> team name)\n  const srcTeamById = {};\n  (srcTeamsR.objects || []).forEach(t => { if (t?.id) srcTeamById[t.id] = t.name || t.title || t.id; });\n\n    // ── DS-like ACL stubs (ne pas perdre une ACL si group_id non résolu) ──\n    const unresolvedAcls = [];\n    __wfd_dd_acl_unresolved = unresolvedAcls;\n    const normKey = (s) => String(s || '').toLowerCase().trim();\n\n    // Étendre la résolution group_id -> name avec /groups (certains ACLs référencent groups non listés dans /teams)\n    const srcGroupsR = await fetch(srcBase + '/API/users/v1/groups/?per_page=500', { headers: srcH })\n      .then(r => r.ok ? r.json() : ({ objects: [] }))\n      .catch(() => ({ objects: [] }));\n    (srcGroupsR.objects || []).forEach(g => { if (g?.id) srcTeamById[String(g.id)] = (g.name || g.title || g.id); });\n\n    // Étendre la map destination name->id avec /groups (en plus de /teams)\n    const dstGroupsR = await fetch(dstBase + '/API/users/v1/groups/?per_page=500', { headers: dstH })\n      .then(r => r.ok ? r.json() : ({ objects: [] }))\n      .catch(() => ({ objects: [] }));\n    (dstGroupsR.objects || []).forEach(g => {\n      const k = normKey(g?.name || g?.title || '');\n      if (k) dstTeamMap[k] = String(g.id);\n    });\n\n    const noteUnresolved = (kind, srcColId, srcColName, srcGroupId, srcGroupName, permissions) => {\n      unresolvedAcls.push({\n        kind,\n        srcColId: String(srcColId || ''),\n        srcColName: String(srcColName || ''),\n        srcGroupId: String(srcGroupId || ''),\n        srcGroupName: srcGroupName ? String(srcGroupName) : null,\n        permissions: Array.isArray(permissions) ? permissions : []\n      });\n    };\n\n    const ensureDstTeamId = async (name) => {\n      const key = normKey(name);\n      if (!key) return null;\n      // Filtrer les teams système si toggle OFF\n      if (!cfg.includeSysTeams && isSystemTeam(key)) return null;\n      if (dstTeamMap[key]) return String(dstTeamMap[key]);\n      // Tentative de création (Teams scope actif) — best effort\n      const r = await fetch(dstBase + '/API/users/v1/teams/', {\n        method: 'POST', headers: dstH, body: JSON.stringify({ name })\n      }).catch(() => null);\n      if (r && r.ok) {\n        const obj = await r.json().catch(() => null);\n        if (obj && obj.id) {\n          dstTeamMap[key] = String(obj.id);\n          return String(obj.id);\n        }\n      }\n      return null;\n    };\n\n  // --- lire listes source pour SS + Storages (en plus des cols/views déjà chargés)\n  const srcSSr = await fetch(srcBase + '/API/search/v1/search/saved/?per_page=500', { headers: srcH })\n    .then(r => r.ok ? r.json() : ({ objects: [] }))\n    .catch(() => ({ objects: [] }));\n\n  const srcStr = await fetch(srcBase + '/API/files/v1/storages/?per_page=500', { headers: srcH })\n    .then(r => r.ok ? r.json() : ({ objects: [] }))\n    .catch(() => ({ objects: [] }));\n\n  // --- index destination : saved searches name/title -> id ; storages name -> id\n  const dstSSr = await fetch(dstBase + '/API/search/v1/search/saved/?per_page=500', { headers: dstH })\n    .then(r => r.ok ? r.json() : ({ objects: [] }))\n    .catch(() => ({ objects: [] }));\n\n  const dstStr = await fetch(dstBase + '/API/files/v1/storages/?per_page=500', { headers: dstH })\n    .then(r => r.ok ? r.json() : ({ objects: [] }))\n    .catch(() => ({ objects: [] }));\n\n  const dstSSMap = {};\n  (dstSSr.objects || []).forEach(s => {\n    const k = String(s.name || s.title || '').toLowerCase().trim();\n    if (k) dstSSMap[k] = s.id;\n  });\n\n  const dstStMap = {};\n  (dstStr.objects || []).forEach(s => {\n    const k = String(s.name || '').toLowerCase().trim();\n    if (k) dstStMap[k] = s.id;\n  });\n\n  // helper: extraire les entrées ACL (direct/inherited/propagates) + convertir permissions\n  const getEntries = (aclData) => (aclData.groups_acl || []); // ✅ direct only (inherited/propagates recalculés)\n\n  const toPerms = (ga) => {\n    const p = (ga.permissions || []).map(x => String(x).toLowerCase());\n    const perms = new Set(['read']);\n    if (p.includes('write') || p.includes('delete') || p.includes('change-acl')) perms.add('write');\n    if (p.includes('delete')) perms.add('delete');\n    if (p.includes('change-acl')) perms.add('change-acl');\n    return [...perms];\n  };\n\n  // helper: pousser une ACL group->object sur la destination\n  const putGroupAcl = async (dstGId, objectType, objectId, perms) => {\n    if (!dstGId || !objectId) return;\n    await fetch(dstBase + '/API/acls/v1/groups/' + dstGId + '/acl/' + objectType + '/' + objectId + '/', {\n      method: 'PUT',\n      headers: dstH,\n      body: JSON.stringify({ permissions: perms })\n    }).catch(() => {});\n  };\n\n  await copyTeamSettingsDD();\n\n // 1) Collections ACLs (direct + propagating) — dépend du scope teams\n if (active.includes('teams') || active.includes('collections')) {\n\n   // Helpers\n   const normTeamKey = (s) => String(s || '').toLowerCase().trim();\n   const toPermsExact = (ga) => {\n     const p = (ga && ga.permissions ? ga.permissions : []).map(x => String(x).toLowerCase());\n     const perms = new Set(p);\n     if (!perms.has('read')) perms.add('read');\n     return [...perms];\n   };\n\n   const srcColList = (srcColsR.objects || []).filter(c => c && c.id);\n   const totalCols = srcColList.length;\n   let doneCols = 0;\n   log('── ACLs collections : ' + totalCols + ' collections à traiter…');\n   \n\n   // Cache dest ACLs (only when needed)\n   const dstAclCache = {}; // dstColId -> aclData\n   const getDstAcl = async (dstColId) => {\n     if (!dstColId) return null;\n     if (dstAclCache[dstColId]) return dstAclCache[dstColId];\n     const d = await fetch(dstBase + '/API/acls/v1/acl/collections/' + dstColId + '/', { headers: dstH })\n       .then(r => r.ok ? r.json() : null)\n       .catch(() => null);\n     dstAclCache[dstColId] = d;\n     return d;\n   };\n\n   // Apply direct group ACL\n   const putDirect = async (dstGId, dstColId, perms) => {\n     if (!dstGId || !dstColId) return false;\n     const r = await fetch(dstBase + '/API/acls/v1/groups/' + dstGId + '/acl/collections/' + dstColId + '/', {\n       method: 'PUT', headers: dstH, body: JSON.stringify({ permissions: perms })\n     }).catch(() => null);\n     return !!(r && r.ok);\n   };\n   const delDirect = async (dstGId, dstColId) => {\n     if (!dstGId || !dstColId) return false;\n     const r = await fetch(dstBase + '/API/acls/v1/groups/' + dstGId + '/acl/collections/' + dstColId + '/', {\n       method: 'DELETE', headers: dstH\n     }).catch(() => null);\n     return !!(r && r.ok);\n   };\n\n   // Apply propagating ACL via /API/acls/v1/acl/_propagating_collections/\n   // Endpoint validé sur tenant Bayard : PUT avec object_keys + group_ids + permissions + user_ids\n   const putProp = async (dstGId, dstColId, perms) => {\n     if (!dstGId || !dstColId) return false;\n     const body = {\n       object_keys: [String(dstColId)],\n       group_ids: [String(dstGId)],\n       permissions: perms,\n       user_ids: []\n     };\n     const r = await fetch(dstBase + '/API/acls/v1/acl/_propagating_collections/', {\n       method: 'PUT', headers: dstH, body: JSON.stringify(body)\n     }).catch(() => null);\n     return !!(r && r.ok);\n   };\n   // Suppression propagating ACL\n   const delProp = async (dstGId, dstColId) => {\n     if (!dstGId || !dstColId) return false;\n     const body = {\n       object_keys: [String(dstColId)],\n       group_ids: [String(dstGId)],\n       user_ids: []\n     };\n     const r = await fetch(dstBase + '/API/acls/v1/acl/_propagating_collections/', {\n       method: 'DELETE', headers: dstH, body: JSON.stringify(body)\n     }).catch(() => null);\n     return !!(r && r.ok);\n   };\n\n   // Main per-collection\n   for (const srcCol of srcColList) {\n     doneCols++;\n\n     if (doneCols % 25 === 0) {\n       log('  ACLs collections : ' + doneCols + '/' + totalCols);\n       await new Promise(r => setTimeout(r, 0));\n     }\n\n     // Résolution dstColId — priorité absolue à ddColIdMap (mapping src→dst construit\n     // pendant la sync hiérarchique). Fallback sur dstColMap (titre) seulement si le\n     // titre est unique (non dupliqué). Si doublon non résolu → skip avec log.\n     const _srcColKey = (srcCol.title||srcCol.name||'').toLowerCase().trim();\n     let dstColId = (ddColIdMap && ddColIdMap[srcCol.id]) || null;\n     if (!dstColId) {\n       if (dstColMapDupes.has(_srcColKey)) {\n         // Titre ambigu sans mapping ddColIdMap → on ne peut pas résoudre sans risque\n         log('  ⚠️ ACL ignorée (titre ambigu, non résolu) : ' + (srcCol.title||srcCol.name||srcCol.id));\n         continue;\n       }\n       dstColId = dstColMap[_srcColKey] || null;\n     }\n     if (!dstColId) continue;\n\n     // Read ACL source\n     const aclData = await fetch(srcBase + '/API/acls/v1/acl/collections/' + srcCol.id + '/', { headers: srcH })\n       .then(r => r.ok ? r.json() : null)\n       .catch(() => null);\n     if (!aclData) continue;\n\n     // Desired sets\n     const desiredDirect = new Map(); // dstGId -> perms\n     const desiredProp = new Map();   // dstGId -> perms\n     // direct\n     for (const ga of (aclData.groups_acl || [])) {\n       const perms = toPermsExact(ga);\n       const srcGroupId = ga && ga.group_id;\n       const srcName = srcTeamById[String(srcGroupId)] || null;\n       if (!srcName) { noteUnresolved('direct', srcCol.id, (srcCol.name || srcCol.title || ''), srcGroupId, null, perms); continue; }\n       // Filtrer les teams système si toggle OFF\n       if (!cfg.includeSysTeams && isSystemTeam(normKey(srcName))) continue;\n       let dstGId = dstTeamMap[normKey(srcName)] || null;\n       if (!dstGId) dstGId = await ensureDstTeamId(srcName);\n       if (!dstGId) { noteUnresolved('direct', srcCol.id, (srcCol.name || srcCol.title || ''), srcGroupId, srcName, perms); continue; }\n       desiredDirect.set(String(dstGId), perms);\n     }\n     // propagating\n     for (const ga of (aclData.propagating_groups_acl || [])) {\n       const perms = toPermsExact(ga);\n       const srcGroupId = ga && ga.group_id;\n       const srcName = srcTeamById[String(srcGroupId)] || null;\n       if (!srcName) { noteUnresolved('propagates', srcCol.id, (srcCol.name || srcCol.title || ''), srcGroupId, null, perms); continue; }\n       // Filtrer les teams système si toggle OFF\n       if (!cfg.includeSysTeams && isSystemTeam(normKey(srcName))) continue;\n       let dstGId = dstTeamMap[normKey(srcName)] || null;\n       if (!dstGId) dstGId = await ensureDstTeamId(srcName);\n       if (!dstGId) { noteUnresolved('propagates', srcCol.id, (srcCol.name || srcCol.title || ''), srcGroupId, srcName, perms); continue; }\n       desiredProp.set(String(dstGId), perms);\n     }\n\n     // Destination ACL snapshot (needed for add_only checks and overwrite deletes)\n     const dstAcl = await getDstAcl(dstColId);\n     const dstDirectSet = new Set(((dstAcl && dstAcl.groups_acl) || []).map(x => String(x.group_id)));\n     const dstPropSet = new Set(((dstAcl && dstAcl.propagating_groups_acl) || []).map(x => String(x.group_id)));\n\n     // OVERWRITE: delete extras (direct)\n     if (mode === 'overwrite') {\n       for (const gid of dstDirectSet) {\n         if (!desiredDirect.has(gid)) await delDirect(gid, dstColId);\n       }\n       for (const gid of dstPropSet) {\n         if (!desiredProp.has(gid)) await delProp(gid, dstColId);\n       }\n     }\n\n     // Apply direct\n     for (const [gid, perms] of desiredDirect.entries()) {\n       if (mode === 'add_only' && dstDirectSet.has(gid)) continue;\n       await putDirect(gid, dstColId, perms);\n     }\n\n     // Apply propagation at the exact level\n     for (const [gid, perms] of desiredProp.entries()) {\n       if (mode === 'add_only' && dstPropSet.has(gid)) continue;\n       await putProp(gid, dstColId, perms);\n     }\n   }\n }\n\n // 2) Metadata Views\n if (active.includes('metadataViews')) {\n  for (const srcView of (srcViewsR.objects || [])) {\n    const dstViewId = dstViewMap[(srcView.name || '').toLowerCase().trim()];\n    if (!dstViewId) continue;\n\n    const aclData = await fetch(srcBase + '/API/acls/v1/acl/metadata_views/' + srcView.id + '/', { headers: srcH })\n      .then(r => r.ok ? r.json() : null)\n      .catch(() => null);\n    if (!aclData) continue;\n\n    // Direct ACLs\n    for (const ga of (aclData.groups_acl || [])) {\n      const srcTeamName = srcTeamById[ga.group_id];\n      if (!srcTeamName) continue;\n      if (!cfg.includeSysTeams && isSystemTeam(normKey(srcTeamName))) continue;\n      const dstGId = dstTeamMap[String(srcTeamName).toLowerCase().trim()];\n      if (!dstGId) continue;\n      await putGroupAcl(dstGId, 'metadata_views', dstViewId, toPerms(ga));\n    }\n    // Propagating ACLs (si présentes sur la source)\n    for (const ga of (aclData.propagating_groups_acl || [])) {\n      const srcTeamName = srcTeamById[ga.group_id];\n      if (!srcTeamName) continue;\n      if (!cfg.includeSysTeams && isSystemTeam(normKey(srcTeamName))) continue;\n      const dstGId = dstTeamMap[String(srcTeamName).toLowerCase().trim()];\n      if (!dstGId) continue;\n      await putGroupAcl(dstGId, 'metadata_views', dstViewId, toPerms(ga));\n    }\n  }\n } // end metadataViews ACLs\n\n // 3) Saved Searches\n if (active.includes('savedSearches')) {\n\n  // Recharger dstSSMap pour inclure les searches créées pendant la synchro\n  const dstSSrFresh = await fetch(dstBase + '/API/search/v1/search/saved/?per_page=500', { headers: dstH })\n    .then(r => r.ok ? r.json() : ({ objects: [] })).catch(() => ({ objects: [] }));\n  (dstSSrFresh.objects || []).forEach(s => {\n    const k = String(s.name || s.title || '').toLowerCase().trim();\n    if (k) dstSSMap[k] = s.id;\n  });\n\n  // Aussi charger les searches des groupes destination\n  const dstGrpsACL = await fetch(dstBase + '/API/search/v1/search/saved/groups/?per_page=500', { headers: dstH })\n    .then(r => r.ok ? r.json() : {}).catch(() => ({}));\n  for (const dstGrp of (dstGrpsACL.objects || [])) {\n    const grpSS = await fetch(dstBase + '/API/search/v1/search/saved/?group_id=' + dstGrp.id + '&per_page=500', { headers: dstH })\n      .then(r => r.ok ? r.json() : {}).catch(() => ({}));\n    (grpSS.objects || []).forEach(s => {\n      const k = String(s.name || '').toLowerCase().trim();\n      if (k && !dstSSMap[k]) dstSSMap[k] = s.id;\n    });\n  }\n\n  // Source : aussi lire les searches des groupes\n  const allSrcSS = [...(srcSSr.objects || [])];\n  const srcGrpsACL = await fetch(srcBase + '/API/search/v1/search/saved/groups/?per_page=500', { headers: srcH })\n    .then(r => r.ok ? r.json() : {}).catch(() => ({}));\n  for (const srcGrp of (srcGrpsACL.objects || [])) {\n    const grpSS = await fetch(srcBase + '/API/search/v1/search/saved/?group_id=' + srcGrp.id + '&per_page=500', { headers: srcH })\n      .then(r => r.ok ? r.json() : {}).catch(() => ({}));\n    (grpSS.objects || []).forEach(s => { if (!allSrcSS.find(x => x.id === s.id)) allSrcSS.push(s); });\n  }\n\n  for (const srcSS of allSrcSS) {\n    const ssName = String(srcSS.name || srcSS.title || '').trim();\n    if (!ssName) continue;\n\n    const dstSSId = dstSSMap[ssName.toLowerCase().trim()];\n    if (!dstSSId) continue;\n\n    const aclData = await fetch(srcBase + '/API/acls/v1/acl/saved_searches/' + srcSS.id + '/', { headers: srcH })\n      .then(r => r.ok ? r.json() : null)\n      .catch(() => null);\n    if (!aclData) continue;\n\n    // Direct ACLs\n    for (const ga of (aclData.groups_acl || [])) {\n      const srcTeamName = srcTeamById[ga.group_id];\n      if (!srcTeamName) continue;\n      if (!cfg.includeSysTeams && isSystemTeam(normKey(srcTeamName))) continue;\n      const dstGId = dstTeamMap[String(srcTeamName).toLowerCase().trim()];\n      if (!dstGId) continue;\n      await putGroupAcl(dstGId, 'saved_searches', dstSSId, toPerms(ga));\n    }\n    // Propagating ACLs\n    for (const ga of (aclData.propagating_groups_acl || [])) {\n      const srcTeamName = srcTeamById[ga.group_id];\n      if (!srcTeamName) continue;\n      if (!cfg.includeSysTeams && isSystemTeam(normKey(srcTeamName))) continue;\n      const dstGId = dstTeamMap[String(srcTeamName).toLowerCase().trim()];\n      if (!dstGId) continue;\n      await putGroupAcl(dstGId, 'saved_searches', dstSSId, toPerms(ga));\n    }\n  }\n } // end savedSearches ACLs\n\n // 4) Custom Actions ACLs\n if (active.includes('customActions')) {\n\n  // Index source custom actions id -> title\n  const srcCAList = (await fetchAllPages(srcBase, srcH, '/API/assets/v1/custom_actions/?per_page=500').catch(()=>[]));\n  // Index destination custom actions title -> id\n  const dstCAList = (await fetchAllPages(dstBase, dstH, '/API/assets/v1/custom_actions/?per_page=500').catch(()=>[]));\n  const dstCAMap = {};\n  (dstCAList || []).forEach(a => {\n    const k = String(a.title || a.name || '').toLowerCase().trim();\n    if (k) dstCAMap[k] = a.id;\n  });\n\n  for (const srcCA of (srcCAList || [])) {\n    const dstCAId = dstCAMap[String(srcCA.title || srcCA.name || '').toLowerCase().trim()];\n    if (!dstCAId) continue;\n\n    const aclData = await fetch(srcBase + '/API/acls/v1/acl/custom_actions/' + srcCA.id + '/', { headers: srcH })\n      .then(r => r.ok ? r.json() : null)\n      .catch(() => null);\n    if (!aclData) continue;\n\n    for (const ga of (aclData.groups_acl || [])) {\n      const srcTeamName = srcTeamById[ga.group_id];\n      if (!srcTeamName) continue;\n      if (!cfg.includeSysTeams && isSystemTeam(normKey(srcTeamName))) continue;\n      const dstGId = dstTeamMap[normKey(srcTeamName)];\n      if (!dstGId) continue;\n      await putGroupAcl(dstGId, 'custom_actions', dstCAId, toPerms(ga));\n    }\n  }\n } // end customActions ACLs\n\n // 5) Storages — volontairement ignoré en DD (pas de partage storages PROD↔DEV/QA)\n if (unresolvedAcls.length) { results.push('⚠️ ACL non résolues : ' + unresolvedAcls.length + ' (voir __wfd_dd_acl_unresolved)'); }\n    results.push('✅ ACLs inter-domaines Teams : Collections/Views/SavedSearches');\n\n    // ── ACLs de gestion des Teams (qui peut gérer quelle team) ──────────────\n    if (active.includes('teams')) {\n      try {\n        // Fetch teams src et dst\n        const [srcTeamsR2, dstTeamsR2] = await Promise.all([\n          fetch(srcBase+'/API/users/v1/teams/?per_page=500',{headers:srcH}).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]})),\n          fetch(dstBase+'/API/users/v1/teams/?per_page=500',{headers:dstH}).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]})),\n        ]);\n        // Maps nom → id pour src et dst (teams + role_groups)\n        const [srcRGsForAcl, dstRGsForAcl] = await Promise.all([\n          fetch(srcBase+'/API/users/v1/role_groups/?per_page=500',{headers:srcH}).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]})),\n          fetch(dstBase+'/API/users/v1/role_groups/?per_page=500',{headers:dstH}).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]})),\n        ]);\n        const srcGroupIdByName = {};\n        [...(srcTeamsR2.objects||[]), ...(srcRGsForAcl.objects||[])].forEach(g=>{if(g?.name) srcGroupIdByName[g.name.toLowerCase().trim()]=g.id;});\n        const dstGroupIdByName2 = {};\n        // D'abord role_groups, puis teams (teams écrasent en priorité)\n        [...(dstRGsForAcl.objects||[]), ...(dstTeamsR2.objects||[])].forEach(g=>{if(g?.name) dstGroupIdByName2[g.name.toLowerCase().trim()]=g.id;});\n        const dstTeamIdByName = {};\n        (dstTeamsR2.objects||[]).forEach(t=>{if(t?.name) dstTeamIdByName[t.name.toLowerCase().trim()]=t.id;});\n\n        let copied=0, skipped=0;\n        for (const srcTeam of (srcTeamsR2.objects||[])) {\n          const teamName = (srcTeam.name||'').toLowerCase().trim();\n          if (!teamName) continue;\n          const dstTeamId = dstTeamIdByName[teamName];\n          if (!dstTeamId) { skipped++; continue; }\n\n          // Fetch ACLs source\n          const srcAcl = await fetch(srcBase+'/API/acls/v1/acl/groups/'+srcTeam.id+'/',{headers:srcH})\n            .then(r=>r.ok?r.json():null).catch(()=>null);\n          if (!srcAcl) { skipped++; continue; }\n\n          const srcGroups = srcAcl.groups_acl||[];\n          if (!srcGroups.length) { skipped++; continue; }\n\n          // Résoudre group_ids src → noms → dst\n          const srcGroupNameById = {};\n          [...(srcTeamsR2.objects||[]), ...(srcRGsForAcl.objects||[])].forEach(g=>{if(g?.id) srcGroupNameById[g.id]=g.name;});\n\n          const dstGroups = srcGroups.map(a => {\n            const grpName = srcGroupNameById[a.group_id];\n            if (!grpName) return null;\n            const dstGid = dstGroupIdByName2[grpName.toLowerCase().trim()];\n            if (!dstGid) return null;\n            return { group_id: dstGid, permissions: a.permissions||[] };\n          }).filter(Boolean);\n\n          if (!dstGroups.length) { skipped++; continue; }\n\n          // 1) Supprimer les ACLs groups existantes sur la team destination\n          const existingAcl = await fetch(dstBase+'/API/acls/v1/acl/groups/'+dstTeamId+'/',{headers:dstH})\n            .then(r=>r.ok?r.json():null).catch(()=>null);\n          // Supprimer TOUS les groups existants (y compris auto-ACL si absente en PROD)\n          for (const eg of (existingAcl?.groups_acl||[])) {\n            await fetch(dstBase+'/API/acls/v1/acl/groups/', {\n              method:'DELETE', headers:dstH,\n              body: JSON.stringify({ object_keys:[dstTeamId], group_ids:[eg.group_id], user_ids:[] })\n            }).catch(()=>null);\n          }\n          // 2) Pousser les ACLs source résolues\n          // Endpoint : PUT /API/acls/v1/acl/groups/ (sans ID dans l'URL)\n          let allOk = true;\n          for (const dstGroup of dstGroups) {\n            const r2 = await fetch(dstBase+'/API/acls/v1/acl/groups/', {\n              method:'PUT', headers:dstH,\n              body: JSON.stringify({\n                object_keys: [dstTeamId],\n                group_ids: [dstGroup.group_id],\n                permissions: dstGroup.permissions||['read','write','delete','change-acl'],\n                user_ids: []\n              })\n            }).catch(()=>null);\n            if (!r2?.ok) allOk = false;\n          }\n          if (allOk) copied++; else skipped++;\n        }\n        const parts=[];\n        if (copied) parts.push(copied+' copiées');\n        if (skipped) parts.push(skipped+' ignorées');\n        results.push('✅ ACLs Teams (gestion)'+(parts.length?' : '+parts.join(', '):''));\n      } catch(e) { results.push('❌ ACLs Teams (gestion) : '+e.message); }\n    }\n}\n\n    // Role Groups → roles + role_categories via PUT /API/users/v1/role_groups/{id}/\n    if (active.includes('roleGroups')) {\n      for (const srcRG of (srcRGsR.objects||[])) {\n        const dstRGId = dstRGMap[(srcRG.name||'').toLowerCase()];\n        if (!dstRGId) continue;\n        await fetch(dstBase+'/API/users/v1/role_groups/'+dstRGId+'/',{\n          method:'PUT', headers:dstH,\n          body: JSON.stringify({\n            roles          : srcRG.roles || [],\n            role_categories: srcRG.role_categories || {},\n          })\n        }).catch(()=>{});\n      }\n      results.push('✅ Role Groups → Rôles créés');\n    }\n  }\n\n  // ── Nettoyage post-DD : supprimer les teams système créées par erreur ──\n  if (!cfg.includeSysTeams) {\n    try {\n      const postDstTeams = await fetch(dstBase+'/API/users/v1/teams/?per_page=500',{headers:dstH}).then(r=>r.ok?r.json():{objects:[]}).catch(()=>({objects:[]}));\n      for (const t of (postDstTeams.objects||[])) {\n        if (isSystemTeam(t.name||'')) {\n          await fetch(dstBase+'/API/users/v1/teams/'+t.id+'/',{method:'DELETE',headers:dstH}).catch(()=>null);\n          results.push('🧹 Team système supprimée post-DD : '+t.name);\n        }\n      }\n    } catch(e) {}\n  }\n\n  \n  results.forEach(r => log(r));\n\n  // ── Rapport ACLs non résolues ──────────────────────────────────────────────\n  if (typeof unresolvedAcls !== 'undefined' && unresolvedAcls && unresolvedAcls.length > 0) {\n    const byCol = {};\n    for (const u of unresolvedAcls) {\n      const key = u.srcColName || u.srcColId;\n      if (!byCol[key]) byCol[key] = [];\n      byCol[key].push((u.srcGroupName || u.srcGroupId) + ' [' + u.kind + ']');\n    }\n    log('⚠️ ACLs non résolues : ' + unresolvedAcls.length + ' entrée(s) sur ' + Object.keys(byCol).length + ' collection(s)');\n    Object.entries(byCol).slice(0, 10).forEach(([col, groups]) => {\n      log('  · ' + col + ' → ' + groups.join(', '));\n    });\n    if (Object.keys(byCol).length > 10) {\n      log('  · … et ' + (Object.keys(byCol).length - 10) + ' autre(s)');\n    }\n  } else if (typeof unresolvedAcls !== 'undefined') {\n    log('✅ ACLs collections : toutes résolues');\n  }\n\n  log('Sync inter-domaines terminée');\n}\n\n// ── Point d'entrée CLI ───────────────────────────────────────────────────────\n\nconst ALL_SCOPES = ['teams','roleGroups','collections','metadataViews','metadata',\n                    'savedSearches','categories','webhooks','customActions',\n                    'automations','relationTypes','systemSettings','exportLocations'];\n\nfunction parseArgs() {\n  const args = process.argv.slice(2);\n  const cfg = {\n    srcBase:        'https://app.iconik.io',\n    srcAppId:       '',\n    srcToken:       '',\n    dstBase:        'https://app.iconik.io',\n    dstAppId:       '',\n    dstToken:       '',\n    mode:           'add_update',\n    scopes:         ALL_SCOPES,\n    includeSysTeams: false,\n    dryRun:         false,\n    jsonOutput:     null,   // chemin fichier JSON de sortie (--json-output)\n  };\n  for (let i = 0; i < args.length; i++) {\n    const a = args[i], v = args[i+1];\n    if (a === '--src-url')           { cfg.srcBase        = v; i++; }\n    else if (a === '--src-appid')    { cfg.srcAppId       = v; i++; }\n    else if (a === '--src-token')    { cfg.srcToken       = v; i++; }\n    else if (a === '--dst-url')      { cfg.dstBase        = v; i++; }\n    else if (a === '--dst-appid')    { cfg.dstAppId       = v; i++; }\n    else if (a === '--dst-token')    { cfg.dstToken       = v; i++; }\n    else if (a === '--mode')         { cfg.mode           = v; i++; }\n    else if (a === '--scopes')       { cfg.scopes         = v.split(',').map(s => s.trim()); i++; }\n    else if (a === '--include-sys-teams') { cfg.includeSysTeams = true; }\n    else if (a === '--dry-run')           { cfg.dryRun         = true; }\n    else if (a === '--json-output')       { cfg.jsonOutput     = v; i++; }\n  }\n  return cfg;\n}\n\n(async () => {\n  const cfg = parseArgs();\n  const startedAt = new Date().toISOString();\n\n  if (!cfg.srcAppId || !cfg.srcToken || !cfg.dstAppId || !cfg.dstToken) {\n    log('ERREUR: credentials manquants (--src-appid, --src-token, --dst-appid, --dst-token)');\n    if (cfg.jsonOutput) writeJsonOutput(cfg.jsonOutput, {\n      status: 'error', exitCode: 2,\n      startedAt, finishedAt: new Date().toISOString(),\n      error: 'credentials manquants',\n      scopes: cfg.scopes, mode: cfg.mode, dryRun: cfg.dryRun,\n      results: []\n    });\n    process.exit(2);\n  }\n\n  log('Iconik Sync DD — ' + cfg.mode + ' — scopes: ' + cfg.scopes.join(', '));\n  if (cfg.dryRun) log('MODE DRY-RUN — aucune écriture');\n\n  // Collecter les lignes de log pour le JSON de sortie\n  const _logLines = [];\n  const _origLog = log;\n  // Monkey-patch log() pour intercepter les messages\n  global._syncLogLines = _logLines;\n\n  try {\n    await lancerDomaineDomaine(cfg);\n    log('Sync terminée');\n    const finishedAt = new Date().toISOString();\n\n    if (cfg.jsonOutput) {\n      writeJsonOutput(cfg.jsonOutput, {\n        status: 'success', exitCode: 0,\n        startedAt, finishedAt,\n        mode: cfg.mode, scopes: cfg.scopes, dryRun: cfg.dryRun,\n        src: cfg.srcBase, dst: cfg.dstBase,\n        results: buildResultsFromLog(_logLines),\n        log: _logLines,\n      });\n    }\n    process.exit(0);\n  } catch(e) {\n    log('ERREUR CRITIQUE: ' + e.message);\n    console.error(e.stack);\n    const finishedAt = new Date().toISOString();\n    if (cfg.jsonOutput) {\n      writeJsonOutput(cfg.jsonOutput, {\n        status: 'error', exitCode: 1,\n        startedAt, finishedAt,\n        mode: cfg.mode, scopes: cfg.scopes, dryRun: cfg.dryRun,\n        src: cfg.srcBase, dst: cfg.dstBase,\n        error: e.message,\n        results: buildResultsFromLog(_logLines),\n        log: _logLines,\n      });\n    }\n    process.exit(1);\n  }\n})();\n\n// ── JSON output helpers ───────────────────────────────────────────────────────\n\nfunction writeJsonOutput(filePath, obj) {\n  try {\n    const fs = require('fs');\n    fs.writeFileSync(filePath, JSON.stringify(obj, null, 2), 'utf-8');\n    log('JSON output écrit : ' + filePath);\n  } catch(e) {\n    log('Erreur ecriture JSON output : ' + e.message);\n  }\n}\n\n// Parse les lignes de log pour extraire un tableau de résultats structurés\n// Format attendu : \"✅ collections : 26 créés, 3 mis à jour\" ou \"❌ teams : ...\"\nfunction buildResultsFromLog(lines) {\n  const results = [];\n  for (const line of (lines || [])) {\n    // Extraire la partie après le timestamp \"[HH:MM:SS] \"\n    const msg = line.replace(/^\\[\\d{2}:\\d{2}:\\d{2}\\]\\s*/, '');\n    const okMatch  = msg.match(/^✅\\s+(\\S+)\\s*(?::\\s*(.+))?$/);\n    const errMatch = msg.match(/^❌\\s+(\\S+)\\s*(?::\\s*(.+))?$/);\n    if (okMatch) {\n      results.push({ scope: okMatch[1], status: 'ok', detail: okMatch[2] || '' });\n    } else if (errMatch) {\n      results.push({ scope: errMatch[1], status: 'error', detail: errMatch[2] || '' });\n    }\n  }\n  return results;\n}\n",
  "proxy.js": "#!/usr/bin/env node\n// =============================================================================\n// Iconik Sync — Serveur local (Node.js)\n// Sert l'UI HTML, proxifie l'API Iconik et exécute sync_dd.js en streaming.\n//\n// Usage : node proxy.js\n// Puis ouvrir : http://localhost:8080/\n// =============================================================================\n\n'use strict';\n\nconst http       = require('http');\nconst https      = require('https');\nconst fs         = require('fs');\nconst path       = require('path');\nconst { spawn }  = require('child_process');\nconst { URL }    = require('url');\n\nconst PORT       = 8080;\nconst ICONIK_API = 'https://app.iconik.io';\nconst SCRIPT_DIR = __dirname;\n\n// ── État du job ──────────────────────────────────────────────────────────────\nlet _logQueue   = [];        // tableau de { type, msg/code }\nlet _logWaiters = [];        // resolve() de promesses en attente\nlet _jobRunning = false;\nlet _jobResult  = null;\n\nfunction pushEvent(ev) {\n  _logQueue.push(ev);\n  const waiters = _logWaiters.splice(0);\n  waiters.forEach(fn => fn());\n}\n\n// ── Utilitaires ──────────────────────────────────────────────────────────────\nfunction corsHeaders() {\n  return {\n    'Access-Control-Allow-Origin':  '*',\n    'Access-Control-Allow-Methods': 'GET, POST, PUT, PATCH, DELETE, OPTIONS',\n    'Access-Control-Allow-Headers': 'App-ID, Auth-Token, Content-Type',\n  };\n}\n\nfunction sendJson(res, obj, code = 200) {\n  const body = JSON.stringify(obj);\n  res.writeHead(code, { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body), ...corsHeaders() });\n  res.end(body);\n}\n\nfunction readBody(req) {\n  return new Promise((resolve, reject) => {\n    const chunks = [];\n    req.on('data', c => chunks.push(c));\n    req.on('end',  () => resolve(Buffer.concat(chunks)));\n    req.on('error', reject);\n  });\n}\n\nfunction log(method, urlPath, status) {\n  const ok = String(status).startsWith('2');\n  const c  = ok ? '\\x1b[92m' : '\\x1b[91m';\n  console.log(`  ${c}${method} ${urlPath} → ${status}\\x1b[0m`);\n}\n\n// ── Servir un fichier statique ────────────────────────────────────────────────\nfunction serveFile(res, filename) {\n  const filePath = path.join(SCRIPT_DIR, filename);\n  if (!fs.existsSync(filePath)) {\n    res.writeHead(404, corsHeaders());\n    res.end('File not found: ' + filename);\n    return;\n  }\n  const data = fs.readFileSync(filePath);\n  res.writeHead(200, {\n    'Content-Type':   'text/html; charset=utf-8',\n    'Content-Length': data.length,\n    ...corsHeaders(),\n  });\n  res.end(data);\n}\n\n// ── Reverse proxy vers Iconik ─────────────────────────────────────────────────\nasync function proxyToIconik(req, res, method, bodyBuf) {\n  const target = new URL(ICONIK_API + req.url);\n  const options = {\n    hostname: target.hostname,\n    port:     target.port || 443,\n    path:     target.pathname + target.search,\n    method,\n    headers: {\n      'App-ID':       req.headers['app-id']       || '',\n      'Auth-Token':   req.headers['auth-token']   || '',\n      'Content-Type': req.headers['content-type'] || 'application/json',\n    },\n  };\n  if (bodyBuf && bodyBuf.length) options.headers['Content-Length'] = bodyBuf.length;\n\n  return new Promise((resolve) => {\n    const proxyReq = https.request(options, (proxyRes) => {\n      const chunks = [];\n      proxyRes.on('data', c => chunks.push(c));\n      proxyRes.on('end', () => {\n        const data = Buffer.concat(chunks);\n        res.writeHead(proxyRes.statusCode, {\n          'Content-Type': proxyRes.headers['content-type'] || 'application/json',\n          ...corsHeaders(),\n        });\n        res.end(data);\n        log(method, req.url, proxyRes.statusCode);\n        resolve();\n      });\n    });\n    proxyReq.on('error', (e) => {\n      sendJson(res, { error: e.message }, 502);\n      log(method, req.url, 502);\n      resolve();\n    });\n    if (bodyBuf && bodyBuf.length) proxyReq.write(bodyBuf);\n    proxyReq.end();\n  });\n}\n\n// ── Lancer le job de sync ─────────────────────────────────────────────────────\nasync function startSync(req, res) {\n  if (_jobRunning) { sendJson(res, { error: 'Job en cours' }, 409); return; }\n\n  const raw  = await readBody(req);\n  const body = raw.length ? JSON.parse(raw) : {};\n\n  const script = path.join(SCRIPT_DIR, 'sync_dd.js');\n  const cmd    = ['node', script];\n\n  if (body.prod_url)    cmd.push('--src-url',    body.prod_url);\n  if (body.prod_app_id) cmd.push('--src-appid',  body.prod_app_id);\n  if (body.prod_token)  cmd.push('--src-token',  body.prod_token);\n  if (body.dev_url)     cmd.push('--dst-url',    body.dev_url);\n  if (body.dev_app_id)  cmd.push('--dst-appid',  body.dev_app_id);\n  if (body.dev_token)   cmd.push('--dst-token',  body.dev_token);\n  if (body.mode)        cmd.push('--mode',        body.mode);\n  if (body.scopes)      cmd.push('--scopes',      body.scopes.join(','));\n  if (body.dry_run)     cmd.push('--dry-run');\n\n  // Vider la queue\n  _logQueue   = [];\n  _logWaiters = [];\n  _jobRunning = true;\n  _jobResult  = null;\n\n  const child = spawn(cmd[0], cmd.slice(1), {\n    cwd:   SCRIPT_DIR,\n    stdio: ['ignore', 'pipe', 'pipe'],\n  });\n\n  let lineBuffer = '';\n\n  function processChunk(chunk) {\n    lineBuffer += chunk.toString('utf-8');\n    const lines = lineBuffer.split('\\n');\n    lineBuffer  = lines.pop(); // garde le fragment incomplet\n    for (const line of lines) {\n      const trimmed = line.trimEnd();\n      if (trimmed) pushEvent({ type: 'log', msg: trimmed });\n    }\n  }\n\n  child.stdout.on('data', processChunk);\n  child.stderr.on('data', processChunk);\n\n  child.on('close', (code) => {\n    if (lineBuffer.trim()) pushEvent({ type: 'log', msg: lineBuffer.trim() });\n    _jobResult  = code;\n    _jobRunning = false;\n    pushEvent({ type: 'done', code });\n  });\n\n  child.on('error', (e) => {\n    _jobRunning = false;\n    _jobResult  = 2;\n    pushEvent({ type: 'error', msg: e.message });\n  });\n\n  sendJson(res, { started: true });\n  log('POST', '/sync', 200);\n}\n\n// ── SSE — stream des logs ─────────────────────────────────────────────────────\nasync function streamLogs(req, res) {\n  res.writeHead(200, {\n    'Content-Type':  'text/event-stream',\n    'Cache-Control': 'no-cache',\n    'Connection':    'keep-alive',\n    ...corsHeaders(),\n  });\n\n  let cursor = 0;\n\n  const keepalive = setInterval(() => {\n    try { res.write(': keepalive\\n\\n'); } catch (_) { clearInterval(keepalive); }\n  }, 15000);\n\n  async function pump() {\n    while (true) {\n      // Envoyer tous les événements disponibles depuis le curseur\n      while (cursor < _logQueue.length) {\n        const ev   = _logQueue[cursor++];\n        const data = JSON.stringify(ev);\n        try {\n          res.write(`data: ${data}\\n\\n`);\n        } catch (_) {\n          clearInterval(keepalive);\n          return;\n        }\n        if (ev.type === 'done' || ev.type === 'error') {\n          clearInterval(keepalive);\n          res.end();\n          return;\n        }\n      }\n\n      // Attendre le prochain événement\n      await new Promise(resolve => {\n        if (cursor < _logQueue.length) { resolve(); return; }\n        _logWaiters.push(resolve);\n        // Timeout de sécurité 20s\n        setTimeout(resolve, 20000);\n      });\n    }\n  }\n\n  req.on('close', () => clearInterval(keepalive));\n  pump();\n  log('GET', '/logs', 200);\n}\n\n// ── Routeur principal ─────────────────────────────────────────────────────────\nconst server = http.createServer(async (req, res) => {\n  const { method, url } = req;\n\n  // OPTIONS (preflight CORS)\n  if (method === 'OPTIONS') {\n    res.writeHead(200, corsHeaders()); res.end(); return;\n  }\n\n  // Fichiers HTML\n  if (method === 'GET' && (url === '/' || url === '/index.html' || url === '/sync_dd_standalone.html')) {\n    serveFile(res, 'sync_dd_standalone.html');\n    log('GET', url, 200);\n    return;\n  }\n\n  // SSE logs\n  if (method === 'GET' && url === '/logs') {\n    await streamLogs(req, res); return;\n  }\n\n  // Statut du job\n  if (method === 'GET' && url === '/status') {\n    sendJson(res, { running: _jobRunning, result: _jobResult });\n    log('GET', '/status', 200);\n    return;\n  }\n\n  // Lancer sync\n  if (method === 'POST' && url === '/sync') {\n    await startSync(req, res); return;\n  }\n\n  // Ignorer favicon et devtools\n  if (url === '/favicon.ico' || url === '/.well-known/appspecific/com.chrome.devtools.json') {\n    res.writeHead(204, corsHeaders()); res.end(); return;\n  }\n\n  // Proxy API Iconik\n  if (url.startsWith('/API/')) {\n    const bodyBuf = await readBody(req);\n    await proxyToIconik(req, res, method, bodyBuf);\n    return;\n  }\n\n  // 404\n  res.writeHead(404, corsHeaders()); res.end();\n  log(method, url, 404);\n});\n\n// ── Démarrage ─────────────────────────────────────────────────────────────────\nserver.listen(PORT, () => {\n  console.log();\n  console.log('  \\x1b[96m\\x1b[1m====================================================\\x1b[0m');\n  console.log('  \\x1b[96m\\x1b[1m  Iconik Sync — Serveur local\\x1b[0m');\n  console.log('  \\x1b[96m\\x1b[1m====================================================\\x1b[0m');\n  console.log();\n  console.log(`  \\x1b[92m▶ http://localhost:${PORT}/\\x1b[0m`);\n  console.log();\n  console.log('  Pour arrêter : Ctrl+C ou fermez cette fenêtre.');\n  console.log();\n});\n\nserver.on('error', (e) => {\n  if (e.code === 'EADDRINUSE') {\n    console.error(`\\n  \\x1b[91m✖ Port ${PORT} déjà utilisé\\x1b[0m`);\n  } else {\n    console.error(`\\n  \\x1b[91m✖ ${e.message}\\x1b[0m`);\n  }\n  process.exit(1);\n});\n\nprocess.on('SIGINT', () => {\n  console.log('\\n  Serveur arrêté.');\n  process.exit(0);\n});\n",
  "lancer.bat": "@echo off\ntitle Iconik Sync — Serveur local\necho.\necho  ====================================================\necho   Iconik Sync — PROD ^> DEV\necho   Demarrage du proxy local...\necho  ====================================================\necho.\necho  Ouverture dans le navigateur : http://localhost:8080/sync_dd_standalone.html\necho  Pour arreter le serveur : fermez cette fenetre ou Ctrl+C\necho.\nstart \"\" http://localhost:8080/sync_dd_standalone.html\nnode proxy.js\npause\n",
  "lancer.sh": "#!/usr/bin/env bash\n# ====================================================\n#  Iconik Sync — PROD > DEV\n#  Démarrage du proxy local (Mac / Linux)\n# ====================================================\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\ncd \"$SCRIPT_DIR\"\n\necho \"\"\necho \" ====================================================\"\necho \"  Iconik Sync — PROD > DEV\"\necho \"  Démarrage du proxy local...\"\necho \" ====================================================\"\necho \"\"\necho \"  Ouverture dans le navigateur : http://localhost:8080/\"\necho \"  Pour arrêter le serveur : Ctrl+C\"\necho \"\"\n\n# Vérifier que node est disponible\nif ! command -v node &>/dev/null; then\n  echo \"  ✖ Node.js introuvable. Installez-le depuis https://nodejs.org\"\n  exit 1\nfi\n\n# Ouvrir le navigateur en arrière-plan (Mac)\nif command -v open &>/dev/null; then\n  sleep 1 && open \"http://localhost:8080/\" &\n# Linux (si disponible)\nelif command -v xdg-open &>/dev/null; then\n  sleep 1 && xdg-open \"http://localhost:8080/\" &\nfi\n\nnode proxy.js\n",
  "README.md": "# Iconik Sync — PROD → DEV\n## Guide d'installation et d'utilisation\n\n---\n\n## Prérequis\n\n- **Node.js** v18 ou supérieur — [nodejs.org](https://nodejs.org)\n- Aucune dépendance npm supplémentaire\n\nVérifier l'installation :\n```\nnode --version\n```\n\n---\n\n## Démarrage rapide\n\n### Windows\nDouble-cliquer sur **`lancer.bat`**\n\n### Mac / Linux\n```bash\nchmod +x lancer.sh   # une seule fois\n./lancer.sh\n```\n\nLe navigateur s'ouvre automatiquement sur `http://localhost:8080/`.  \nPour arrêter le serveur : **Ctrl+C** dans la fenêtre de terminal, ou fermez-la.\n\n---\n\n## Création des App Tokens Iconik\n\nLa synchronisation nécessite deux App Tokens Iconik : un pour la source (PROD), un pour la destination (DEV/Staging).\n\n### Où créer un App Token\nDans Iconik : **Settings → App Tokens → Create App Token**\n\n### Convention de nommage — règle obligatoire\n\n> Le nom du token **doit contenir** le mot `PROD` ou `DEV` selon son environnement.\n\n| Environnement | Exemples de noms valides |\n|---|---|\n| Production | `Sync-PROD`, `MAM-PROD-Sync`, `BAYARD-PROD` |\n| Dev / Staging | `Sync-DEV`, `MAM-DEV-Sync`, `STAGING-DEV` |\n\n**Pourquoi cette règle est obligatoire :**  \nL'interface vérifie automatiquement le nom du token dès sa saisie. Si un token `PROD` est renseigné dans le champ DEV (ou inversement), un avertissement s'affiche et le lancement est bloqué. Cette protection évite d'écraser accidentellement la production.\n\n### Permissions recommandées\nLe token doit avoir accès en lecture/écriture aux ressources à synchroniser (collections, metadata, teams, etc.). Un token admin est conseillé pour la source (lecture seule suffisante) et la destination (lecture + écriture requise).\n\n---\n\n## Interface — guide des champs\n\n### Connexion\n\n| Champ | Description |\n|---|---|\n| **Nom** | Étiquette affichée dans les confirmations (ex: `PROD`, `DEV`) |\n| **URL Iconik** | Laisser `https://app.iconik.io` sauf instance on-premise |\n| **App ID** | Identifiant de l'application token (visible dans Settings → App Tokens) |\n| **Auth Token** | Valeur secrète du token |\n\nDès la saisie du App ID et du Auth Token, l'interface interroge Iconik pour vérifier le nom du token et affiche :\n- ✅ `Mon-Token-PROD` — token reconnu, nom cohérent avec le champ\n- ⚠️ `ATTENTION : token DEV dans le champ PROD !` — inversion détectée, lancement bloqué\n- ❌ `Credentials invalides` — App ID ou Token incorrect\n\n### Périmètre (scopes)\n\nCocher les éléments à synchroniser. Par défaut tout est coché.\n\n| Scope | Contenu |\n|---|---|\n| 👥 Teams | Groupes utilisateurs et leurs paramètres |\n| 🎭 Role Groups | Groupes de rôles et permissions |\n| 📁 Collections | Arborescence complète + ACLs |\n| 📋 MD Views | Vues de métadonnées et leurs champs |\n| 🏷️ Métadonnées | Champs de métadonnées |\n| 🔍 Saved Searches | Recherches sauvegardées |\n| 🗂️ Catégories | Catégories de métadonnées |\n| 🔗 Webhooks | Webhooks (créés désactivés sur destination) |\n| ⚡ Custom Actions | Actions personnalisées (désactivées sur destination) |\n| 🤖 Automations | Automatisations (créées INACTIVE sur destination) |\n| 🔗 Relation Types | Types de relations entre assets |\n| ⚙️ Share Settings | Paramètres de partage |\n| 📤 Export Locations | Destinations d'export (sans storage) + ACLs |\n\n### Mode de synchronisation\n\n| Mode | Comportement |\n|---|---|\n| 🔄 **Ajouter + Mettre à jour** | Crée les éléments manquants, met à jour les existants. Ne supprime rien. *Mode recommandé.* |\n| ➕ **Ajouter uniquement** | Crée uniquement les éléments absents. Ne modifie pas les existants. |\n| ⚠️ **Écraser tout** | Purge la destination puis recrée depuis la source. Demande confirmation. |\n\n> **Mode Écraser tout** : les teams contenant des utilisateurs ne peuvent pas être supprimées (comportement Iconik). Elles sont mises à jour sans suppression.\n\n### Dry-run\nCocher **Dry-run** pour simuler la synchronisation sans aucune écriture. Le journal affiche ce qui serait fait.\n\n---\n\n## Confirmations de sécurité\n\nSelon la configuration, une ou plusieurs confirmations sont demandées avant le lancement :\n\n1. **Token inversé** → lancement bloqué si un token PROD est dans le champ DEV ou inversement\n2. **Destination \"prod\"** → si le champ Nom de la destination contient \"prod\", saisir `CONFIRMER`\n3. **Mode Écraser tout** → saisir `OVERWRITE` pour confirmer\n4. **Confirmation finale** → résumé de l'opération avant exécution\n\n---\n\n## Journal et export\n\nPendant et après la synchronisation :\n- Le **journal** affiche le détail de chaque opération en temps réel\n- La **barre de progression** reflète l'avancement réel (les collections et ACLs représentent ~75% du temps total)\n- Le bouton **Exporter** sauvegarde le journal en `.txt`\n\n---\n\n## Usage en ligne de commande (orchestrateur)\n\n`sync_dd.js` est utilisable directement sans l'interface HTML :\n\n```bash\nnode sync_dd.js \\\n  --src-appid <APP_ID_PROD> \\\n  --src-token <TOKEN_PROD> \\\n  --dst-appid <APP_ID_DEV> \\\n  --dst-token <TOKEN_DEV> \\\n  --mode add_update \\\n  --scopes teams,collections,metadata,metadataViews \\\n  [--src-url https://app.iconik.io] \\\n  [--dst-url https://app.iconik.io] \\\n  [--include-sys-teams] \\\n  [--dry-run]\n```\n\n### Scopes disponibles\n`teams`, `roleGroups`, `collections`, `metadataViews`, `metadata`, `savedSearches`, `categories`, `webhooks`, `customActions`, `automations`, `relationTypes`, `systemSettings`\n\n### Codes de sortie\n| Code | Signification |\n|---|---|\n| `0` | Succès |\n| `1` | Erreur critique (exception non gérée) |\n| `2` | Credentials manquants ou invalides |\n\n---\n\n## Comportements notables\n\n- **Collections** : synchronisation hiérarchique complète (parent → enfant), avec résolution des doublons de noms par chemin complet\n- **ACLs** : copiées collection par collection depuis la source, avec résolution des groupes par nom\n- **Webhooks / Custom Actions** : créés désactivés sur la destination pour éviter les déclenchements accidentels\n- **Automations** : créées en statut `INACTIVE`\n- **Storages** : non synchronisés (infrastructure-dépendants), à configurer manuellement\n- **Export Locations** : synchronisées sans le champ storage (infrastructure-dépendant) ; ACLs teams et users copiées par nom/email\n- **App Tokens dans Custom Actions** : à reconfigurer manuellement sur la destination\n- **Direction** : PROD → DEV uniquement. L'interface ne permet pas l'opération inverse.\n\n---\n\n## Mirror Check\n\nLe bouton **🔍 Lancer le Mirror Check** compare Source et Destination pour les scopes cochés, sans effectuer aucune écriture.\n\n### Modes\n\n| Option | Comportement |\n|---|---|\n| Sans ACLs | Présence/absence de chaque entité + paramètres (webhooks, export locations…) |\n| 🔐 Vérifier les ACLs | Ajoute la comparaison ACLs pour collections et export locations |\n\n### Scopes vérifiés\n\n| Scope | Ce qui est comparé |\n|---|---|\n| 👥 Teams | Présence/absence (hors système) |\n| 🎭 Role Groups | Présence/absence |\n| 🏷️ Métadonnées | Présence/absence (case-sensitive) + détection doublons de casse |\n| 📋 MD Views | Présence/absence + champs de chaque vue + ACLs (si activé) |\n| 🔍 Saved Searches | Présence/absence + ACLs (si activé) |\n| 📁 Collections | Présence/absence + ACLs par nombre de groupes (si activé) |\n| 🗂️ Catégories | Présence/absence |\n| 🔗 Webhooks | Présence/absence + url, event_type, realm, operation |\n| ⚡ Custom Actions | Présence/absence + ACLs (si activé) |\n| 🤖 Automations | Présence des actives (inactives en dst = intentionnel) |\n| 🔗 Relation Types | Présence/absence (custom uniquement) |\n| ⚙️ Share Settings | Comparaison des clés principales |\n| 📤 Export Locations | Présence/absence + path, options d'export + ACLs (si activé) |\n\n### Journal\n\n- ✅ Conforme\n- ⚠️ Divergence (présent des deux côtés mais différent)\n- ❌ Manquant en destination\n\nLe journal est exportable via **💾 Exporter**.\n\n---\n\n## Dépannage\n\n**\"Port 8080 déjà utilisé\"**  \nUn autre processus utilise le port. Fermer l'autre application ou redémarrer.\n\n**\"Credentials invalides\"**  \nVérifier que l'App ID et le Auth Token correspondent bien au même token dans Iconik (Settings → App Tokens).\n\n**\"node: command not found\"**  \nNode.js n'est pas installé ou pas dans le PATH. Installer depuis [nodejs.org](https://nodejs.org) et relancer le terminal.\n\n**Le navigateur ne s'ouvre pas automatiquement**  \nOuvrir manuellement `http://localhost:8080/` dans le navigateur.\n\n**La barre de progression reste bloquée**  \nLe traitement est en cours. Les collections (722+ items) et leurs ACLs peuvent prendre 8–12 minutes selon la volumétrie. Le journal en bas affiche les étapes en temps réel.\n"
};

  // ── Helpers UI ──────────────────────────────────────────────────────────────

  function kitStatus(msg, isErr) {
    const el = document.getElementById('kit-status');
    if (el) {
      el.textContent = msg;
      el.style.color = isErr ? 'var(--c-danger)' : 'var(--accent)';
    }
  }

  function downloadBlob(blob, filename) {
    const url = URL.createObjectURL(blob);
    const a = Object.assign(document.createElement('a'), { href: url, download: filename });
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  }

  // ── Générateur ZIP (stored, sans compression) ────────────────────────────────
  // Implémentation ZIP spec PKWARE — fichiers stockés sans compression (method 0).
  // Suffisant pour des fichiers texte livrés en kit, zéro dépendance externe.

  function makeZip(fileMap) {
    const enc    = new TextEncoder();
    const u32le  = (n) => [(n>>>0)&0xff,(n>>>8)&0xff,(n>>>16)&0xff,(n>>>24)&0xff];
    const u16le  = (n) => [(n>>>0)&0xff,(n>>>8)&0xff];

    // CRC-32 table
    const crcTable = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      crcTable[i] = c;
    }
    function crc32(buf) {
      let crc = 0xFFFFFFFF;
      for (let i = 0; i < buf.length; i++) crc = crcTable[(crc ^ buf[i]) & 0xff] ^ (crc >>> 8);
      return (crc ^ 0xFFFFFFFF) >>> 0;
    }

    function concat(...arrays) {
      const total = arrays.reduce((s, a) => s + a.length, 0);
      const out = new Uint8Array(total);
      let off = 0;
      for (const a of arrays) { out.set(a, off); off += a.length; }
      return out;
    }

    const localHeaders  = [];
    const centralDirs   = [];
    const offsets       = [];
    let   offset        = 0;
    const now           = new Date();
    // DOS date/time
    const dosTime = ((now.getHours()<<11)|(now.getMinutes()<<5)|(now.getSeconds()>>1));
    const dosDate = (((now.getFullYear()-1980)<<9)|((now.getMonth()+1)<<5)|now.getDate());

    for (const [name, content] of Object.entries(fileMap)) {
      const nameBytes = enc.encode(name);
      const dataBytes = enc.encode(content);
      const crc       = crc32(dataBytes);
      const size      = dataBytes.length;

      // Local file header (signature 0x04034b50)
      const lh = new Uint8Array([
        0x50,0x4b,0x03,0x04,  // signature
        0x14,0x00,            // version needed: 2.0
        0x00,0x00,            // general flags
        0x00,0x00,            // compression: stored
        ...u16le(dosTime),
        ...u16le(dosDate),
        ...u32le(crc),
        ...u32le(size),       // compressed size
        ...u32le(size),       // uncompressed size
        ...u16le(nameBytes.length),
        0x00,0x00,            // extra field length
        ...nameBytes,
      ]);

      offsets.push(offset);
      localHeaders.push(concat(lh, dataBytes));
      offset += lh.length + dataBytes.length;

      // Central directory entry (signature 0x02014b50)
      const cd = new Uint8Array([
        0x50,0x4b,0x01,0x02,  // signature
        0x14,0x00,            // version made by: 2.0
        0x14,0x00,            // version needed
        0x00,0x00,            // general flags
        0x00,0x00,            // compression: stored
        ...u16le(dosTime),
        ...u16le(dosDate),
        ...u32le(crc),
        ...u32le(size),
        ...u32le(size),
        ...u16le(nameBytes.length),
        0x00,0x00,            // extra field length
        0x00,0x00,            // comment length
        0x00,0x00,            // disk number start
        0x00,0x00,            // internal attr
        0x00,0x00,0x00,0x00,  // external attr
        ...u32le(offsets[offsets.length - 1]),
        ...nameBytes,
      ]);
      centralDirs.push(cd);
    }

    const cdOffset = offset;
    const cdSize   = centralDirs.reduce((s, a) => s + a.length, 0);
    const count    = localHeaders.length;

    // End of central directory (signature 0x06054b50)
    const eocd = new Uint8Array([
      0x50,0x4b,0x05,0x06,
      0x00,0x00,            // disk number
      0x00,0x00,            // disk with CD
      ...u16le(count),      // entries on disk
      ...u16le(count),      // total entries
      ...u32le(cdSize),
      ...u32le(cdOffset),
      0x00,0x00,            // comment length
    ]);

    return concat(...localHeaders, ...centralDirs, eocd);
  }

  // ── Générateur kit ───────────────────────────────────────────────────────────

  async function genererKit() {
    kitStatus('⏳ Génération du kit…');
    try {
      const zipBytes = makeZip(KIT_FILES);
      const blob = new Blob([zipBytes], { type: 'application/zip' });
      downloadBlob(blob, ZIP_NAME);
      kitStatus('✅ ' + ZIP_NAME + ' téléchargé — ' + Object.keys(KIT_FILES).length + ' fichiers (v' + KIT_VERSION + ')');
    } catch(e) {
      kitStatus('❌ Erreur : ' + e.message, true);
      console.error('[script-kit]', e);
    }
  }

  // ── Exposition globale ───────────────────────────────────────────────────────

  window.genererKit        = genererKit;
  window.genererKitComplet = genererKit;
  window.genererKitHTML    = genererKit;
  window.genererKitPython  = function () { kitStatus('ℹ️ Export Python supprimé — utilisez le kit complet.'); };
  window.genererKitPostman = function () { kitStatus('ℹ️ Export Postman supprimé — utilisez le kit complet.'); };

})();
